export enum UserRole {
  ADMIN = 'Administrador',
  COMERCIAL = 'Comercial',
  AUDITOR = 'Auditor',
  TECNICO = 'Técnico'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  avatar?: string;
}

export interface Client {
  id: string;
  name: string;
  address: string;
  contactPerson: string;
  email: string;
  phone: string;
  lastVisit?: string;
  status: 'Ativo' | 'Inativo';
}

export interface AuditCriteria {
  id: string;
  label: string;
  status: 'pass' | 'fail' | 'na' | null; // Pass, Fail, Not Applicable, Not Set
  notes: string;
}

export interface Report {
  id: string;
  clientId: string;
  clientName: string; // Denormalized for easier display
  auditorId: string;
  auditorName: string;
  date: string; // ISO Date
  time: string;
  type: 'Visita' | 'Auditoria' | 'Manutenção';
  criteria: AuditCriteria[];
  summary: string; // AI Generated or Manual
  auditorSignature: string | null; // Base64 data URL
  clientSignature: string | null; // Base64 data URL
  status: 'Rascunho' | 'Finalizado';
}

import { GoogleGenAI } from "@google/genai";
import { AuditCriteria } from "../types";

const apiKey = process.env.API_KEY || '';
// Initialize properly with new GoogleGenAI({ apiKey: ... })
// NOTE: In a real app, never expose keys on client side without proxy. 
// For this demo, we assume process.env is injected.
const ai = new GoogleGenAI({ apiKey });

export const generateReportSummary = async (
  clientName: string,
  type: string,
  criteria: AuditCriteria[]
): Promise<string> => {
  if (!apiKey) return "Erro: Chave de API não configurada.";

  const failedItems = criteria.filter(c => c.status === 'fail');
  const passItems = criteria.filter(c => c.status === 'pass');
  const naItems = criteria.filter(c => c.status === 'na');

  const prompt = `
    Atue como um auditor técnico profissional sénior.
    Escreva um resumo executivo curto (máximo 3 parágrafos) em Português de Portugal para um relatório de ${type} realizado no cliente "${clientName}".

    Dados da Auditoria:
    - Total de critérios avaliados: ${criteria.length}
    - Critérios Aprovados: ${passItems.length}
    - Critérios Reprovados: ${failedItems.length}
    - Critérios Não Aplicáveis: ${naItems.length}

    Detalhes das falhas (se houver):
    ${failedItems.map(i => `- ${i.label}: ${i.notes}`).join('\n')}

    Destaques positivos (se houver notas):
    ${passItems.filter(i => i.notes).map(i => `- ${i.label}: ${i.notes}`).join('\n')}

    O tom deve ser profissional, construtivo e focado em melhoria contínua. Se houver falhas, sugira prioridade na resolução.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar o resumo.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao comunicar com a IA para gerar o resumo. Verifique a ligação ou a chave API.";
  }
};

import React, { useRef, useState, useEffect } from 'react';
import { Eraser } from 'lucide-react';

interface SignaturePadProps {
  label: string;
  onEnd: (dataUrl: string | null) => void;
  initialData?: string | null;
  disabled?: boolean;
}

const SignaturePad: React.FC<SignaturePadProps> = ({ label, onEnd, initialData, disabled = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [hasSignature, setHasSignature] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas && initialData) {
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = initialData;
      img.onload = () => {
        ctx?.drawImage(img, 0, 0);
        setHasSignature(true);
      };
    }
  }, [initialData]);

  const getCoordinates = (event: MouseEvent | TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();

    let clientX, clientY;

    if ((event as TouchEvent).touches) {
      clientX = (event as TouchEvent).touches[0].clientX;
      clientY = (event as TouchEvent).touches[0].clientY;
    } else {
      clientX = (event as MouseEvent).clientX;
      clientY = (event as MouseEvent).clientY;
    }

    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    if (disabled) return;
    setIsDrawing(true);
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.lineWidth = 2;
    ctx.lineCap = 'round';
    ctx.strokeStyle = '#000000';

    const { x, y } = getCoordinates(e.nativeEvent as any);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || disabled) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { x, y } = getCoordinates(e.nativeEvent as any);
    ctx.lineTo(x, y);
    ctx.stroke();
    setHasSignature(true);
  };

  const stopDrawing = () => {
    if (disabled) return;
    setIsDrawing(false);
    if (canvasRef.current && hasSignature) {
      onEnd(canvasRef.current.toDataURL());
    }
  };

  const clear = () => {
    if (disabled) return;
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx?.clearRect(0, 0, canvas.width, canvas.height);
      setHasSignature(false);
      onEnd(null);
    }
  };

  return (
    <div className="flex flex-col gap-2">
      <div className="flex justify-between items-center">
        <label className="text-sm font-semibold text-gray-700">{label}</label>
        {!disabled && (
          <button 
            type="button"
            onClick={clear}
            className="text-xs flex items-center gap-1 text-red-600 hover:text-red-800"
          >
            <Eraser size={14} /> Limpar
          </button>
        )}
      </div>
      <div className={`border-2 border-dashed ${disabled ? 'bg-gray-100 border-gray-300' : 'bg-white border-gray-400'} rounded-lg overflow-hidden touch-none`}>
        <canvas
          ref={canvasRef}
          width={400}
          height={160}
          className="w-full h-40 cursor-crosshair"
          onMouseDown={startDrawing}
          onMouseMove={draw}
          onMouseUp={stopDrawing}
          onMouseLeave={stopDrawing}
          onTouchStart={startDrawing}
          onTouchMove={draw}
          onTouchEnd={stopDrawing}
        />
      </div>
      {!hasSignature && !disabled && (
        <p className="text-xs text-amber-600">Assinatura obrigatória</p>
      )}
    </div>
  );
};

export default SignaturePad;

import React, { useState, useEffect } from 'react';
import { Report, Client, User, AuditCriteria } from '../types';
import { DEFAULT_CRITERIA } from '../constants';
import SignaturePad from './SignaturePad';
import { generateReportSummary } from '../services/geminiService';
import { Save, X, Bot, CheckCircle, AlertCircle, MinusCircle, Loader2 } from 'lucide-react';

interface ReportFormProps {
  client: Client;
  auditor: User;
  onSave: (report: Report) => void;
  onCancel: () => void;
}

const ReportForm: React.FC<ReportFormProps> = ({ client, auditor, onSave, onCancel }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [time, setTime] = useState(new Date().toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));
  const [type, setType] = useState<Report['type']>('Visita');
  const [criteria, setCriteria] = useState<AuditCriteria[]>(JSON.parse(JSON.stringify(DEFAULT_CRITERIA)));
  const [summary, setSummary] = useState('');
  const [auditorSignature, setAuditorSignature] = useState<string | null>(null);
  const [clientSignature, setClientSignature] = useState<string | null>(null);
  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const handleCriteriaStatusChange = (id: string, status: AuditCriteria['status']) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, status } : c));
  };

  const handleCriteriaNotesChange = (id: string, notes: string) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, notes } : c));
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingAI(true);
    const result = await generateReportSummary(client.name, type, criteria);
    setSummary(result);
    setIsGeneratingAI(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditorSignature || !clientSignature) {
      alert("Ambas as assinaturas são obrigatórias.");
      return;
    }

    const newReport: Report = {
      id: `r-${Date.now()}`,
      clientId: client.id,
      clientName: client.name,
      auditorId: auditor.id,
      auditorName: auditor.name,
      date,
      time,
      type,
      criteria,
      summary,
      auditorSignature,
      clientSignature,
      status: 'Finalizado'
    };
    onSave(newReport);
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col h-full bg-gray-50">
      {/* Sticky Header */}
      <div className="sticky top-0 z-20 bg-white border-b shadow-sm px-6 py-4 flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Novo Relatório</h2>
          <p className="text-sm text-gray-500">{client.name}</p>
        </div>
        <div className="flex gap-3">
          <button type="button" onClick={onCancel} className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg font-medium hover:bg-gray-200">
            Cancelar
          </button>
          <button type="submit" className="px-6 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200">
            <Save size={18} /> Finalizar
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 max-w-4xl mx-auto w-full">

        {/* Info Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-3 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
            <input 
              type="date" 
              value={date} 
              onChange={e => setDate(e.target.value)}
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Hora</label>
            <input 
              type="time" 
              value={time}
              onChange={e => setTime(e.target.value)} 
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Tipo</label>
            <select 
              value={type} 
              onChange={e => setType(e.target.value as any)}
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
            >
              <option value="Visita">Visita Comercial</option>
              <option value="Auditoria">Auditoria Técnica</option>
              <option value="Manutenção">Manutenção</option>
            </select>
          </div>
        </div>

        {/* Criteria Evaluation - Tablet Optimized Touch Targets */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="bg-gray-50 px-6 py-4 border-b border-gray-100">
            <h3 className="text-lg font-semibold text-gray-800">Critérios de Avaliação</h3>
          </div>
          <div className="divide-y divide-gray-100">
            {criteria.map((item) => (
              <div key={item.id} className="p-6 hover:bg-gray-50 transition-colors">
                <p className="font-medium text-gray-900 mb-4 text-lg">{item.label}</p>

                <div className="flex flex-col md:flex-row gap-4 md:items-start">
                  {/* Status Buttons */}
                  <div className="flex gap-2 flex-shrink-0">
                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'pass')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'pass' 
                          ? 'bg-green-50 border-green-500 text-green-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-green-200'
                      }`}
                    >
                      <CheckCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">Aprovado</span>
                    </button>

                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'fail')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'fail' 
                          ? 'bg-red-50 border-red-500 text-red-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-red-200'
                      }`}
                    >
                      <AlertCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">Falha</span>
                    </button>

                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'na')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'na' 
                          ? 'bg-gray-100 border-gray-500 text-gray-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-gray-300'
                      }`}
                    >
                      <MinusCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">N/A</span>
                    </button>
                  </div>

                  {/* Notes Input */}
                  <div className="flex-1">
                    <textarea
                      placeholder="Observações..."
                      value={item.notes}
                      onChange={e => handleCriteriaNotesChange(item.id, e.target.value)}
                      rows={3}
                      className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none text-base"
                    />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* AI Summary Section */}
        <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-indigo-900 flex items-center gap-2">
              <Bot size={24} /> Resumo e Conclusões
            </h3>
            <button
              type="button"
              onClick={handleGenerateSummary}
              disabled={isGeneratingAI}
              className="text-sm bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2 transition-all"
            >
              {isGeneratingAI ? <Loader2 className="animate-spin" size={16}/> : <Bot size={16}/>}
              {summary ? 'Regerar com IA' : 'Gerar Resumo IA'}
            </button>
          </div>
          <textarea
            value={summary}
            onChange={e => setSummary(e.target.value)}
            placeholder="Escreva um resumo ou utilize a IA para gerar com base nos critérios acima..."
            className="w-full p-4 border border-indigo-200 rounded-lg bg-white h-40 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
        </div>

        {/* Signatures */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pb-12">
          <SignaturePad 
            label={`Assinatura do Auditor (${auditor.name})`}
            onEnd={setAuditorSignature}
          />
          <SignaturePad 
            label={`Assinatura do Cliente (${client.contactPerson})`}
            onEnd={setClientSignature}
          />
        </div>

      </div>
    </form>
  );
};

export default ReportForm;

