          )}

          {/* Settings / Placeholders */}
          {currentScreen === Screen.SETTINGS && (
             <div className="flex flex-col items-center justify-center h-full text-gray-400">
               <Settings size={48} className="mb-4" />
               <h3 className="text-xl font-medium">Configurações de Sistema</h3>
               <p>Apenas acessível a Administradores.</p>
             </div>
          )}

        </div>

        {/* Mobile Bottom Nav */}
        <div className="md:hidden bg-white border-t border-gray-200 flex justify-around p-2 sticky bottom-0 z-20">
          <button onClick={() => setCurrentScreen(Screen.DASHBOARD)} className={`p-2 rounded-lg flex flex-col items-center ${currentScreen === Screen.DASHBOARD ? 'text-blue-600' : 'text-gray-400'}`}>
            <LayoutDashboard size={24} />
            <span className="text-xs mt-1">Inicio</span>
          </button>
          <button onClick={() => setCurrentScreen(Screen.CLIENTS)} className={`p-2 rounded-lg flex flex-col items-center ${currentScreen === Screen.CLIENTS ? 'text-blue-600' : 'text-gray-400'}`}>
            <Users size={24} />
            <span className="text-xs mt-1">Clientes</span>
          </button>
          <button onClick={() => setCurrentScreen(Screen.REPORTS)} className={`p-2 rounded-lg flex flex-col items-center ${currentScreen === Screen.REPORTS ? 'text-blue-600' : 'text-gray-400'}`}>
            <FileText size={24} />
            <span className="text-xs mt-1">Relatórios</span>
          </button>
        </div>
      </main>
    </div>
  );
};

