import React, { useState, useEffect } from 'react';
import { Report, Client, User, AuditCriteria, ReportTemplate } from '../types';
import SignaturePad from './SignaturePad';
import { generateReportSummary } from '../services/geminiService';
import { Save, Bot, CheckCircle, AlertCircle, MinusCircle, Loader2 } from 'lucide-react';

interface ReportFormProps {
  client: Client;
  auditor: User;
  template: ReportTemplate;
  onSave: (report: Report) => void;
  onCancel: () => void;
}

const ReportForm: React.FC<ReportFormProps> = ({ client, auditor, template, onSave, onCancel }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [time, setTime] = useState(new Date().toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));

  // Initialize criteria from template
  const [criteria, setCriteria] = useState<AuditCriteria[]>(
    template.defaultCriteria.map((c, idx) => ({
      id: `crit-${idx}`,
      label: c.label,
      status: null,
      notes: ''
    }))
  );

  const [summary, setSummary] = useState('');

  // Signature States
  const [auditorName, setAuditorName] = useState(auditor.name);
  const [auditorSignature, setAuditorSignature] = useState<string | null>(null);

  const [clientName, setClientName] = useState(client.contactPerson);
  const [clientSignature, setClientSignature] = useState<string | null>(null);

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);

  const handleCriteriaStatusChange = (id: string, status: AuditCriteria['status']) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, status } : c));
  };

  const handleCriteriaNotesChange = (id: string, notes: string) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, notes } : c));
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingAI(true);
    const result = await generateReportSummary(client.name, template.label, criteria);
    setSummary(result);
    setIsGeneratingAI(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditorSignature || !clientSignature) {
      alert("Ambas as assinaturas são obrigatórias.");
      return;
    }
    if (!auditorName.trim() || !clientName.trim()) {
      alert("Os nomes dos signatários são obrigatórios.");
      return;
    }

    const newReport: Report = {
      id: `r-${Date.now()}`,
      clientId: client.id,
      clientName: client.name,
      auditorId: auditor.id,
      auditorName: auditor.name, // Logged in user (could be different from signer name technically, but usually same)
      date,
      time,
      typeKey: template.key,
      typeName: template.label,
      criteria,
      summary,
      auditorSignerName: auditorName,
      auditorSignature,
      clientSignerName: clientName,
      clientSignature,
      status: 'Finalizado'
    };
    onSave(newReport);
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col h-full bg-gray-50">
      {/* Sticky Header */}
      <div className="sticky top-0 z-20 bg-white border-b shadow-sm px-6 py-4 flex justify-between items-center">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Novo Relatório</h2>
          <p className="text-sm font-semibold text-blue-600">{template.label}</p>
          <p className="text-xs text-gray-500">{client.name}</p>
        </div>
        <div className="flex gap-3">
          <button type="button" onClick={onCancel} className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg font-medium hover:bg-gray-200">
            Cancelar
          </button>
          <button type="submit" className="px-6 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200">
            <Save size={18} /> Finalizar
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 max-w-4xl mx-auto w-full">

        {/* Info Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
            <input 
              type="date" 
              value={date} 
              onChange={e => setDate(e.target.value)}
              className="w-full p-3 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Hora</label>
            <input 
              type="time" 
              value={time}
              onChange={e => setTime(e.target.value)} 
              className="w-full p-3 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
            />
          </div>
        </div>

        {/* Criteria Evaluation */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="bg-gray-50 px-6 py-4 border-b border-gray-100">
            <h3 className="text-lg font-semibold text-gray-800">Grelha de Avaliação</h3>
          </div>
          <div className="divide-y divide-gray-100">
            {criteria.map((item) => (
              <div key={item.id} className="p-6 hover:bg-gray-50 transition-colors">
                <p className="font-medium text-gray-900 mb-4 text-lg">{item.label}</p>

                <div className="flex flex-col md:flex-row gap-4 md:items-start">
                  {/* Status Buttons */}
                  <div className="flex gap-2 flex-shrink-0">
                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'pass')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'pass' 
                          ? 'bg-green-50 border-green-500 text-green-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-green-200'
                      }`}
                    >
                      <CheckCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">OK</span>
                    </button>

                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'fail')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'fail' 
                          ? 'bg-red-50 border-red-500 text-red-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-red-200'
                      }`}
                    >
                      <AlertCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">NOK</span>
                    </button>

                    <button
                      type="button"
                      onClick={() => handleCriteriaStatusChange(item.id, 'na')}
                      className={`flex-1 md:flex-none flex flex-col items-center justify-center p-3 w-24 rounded-lg border-2 transition-all ${
                        item.status === 'na' 
                          ? 'bg-gray-100 border-gray-500 text-gray-700' 
                          : 'bg-white border-gray-200 text-gray-400 hover:border-gray-300'
                      }`}
                    >
                      <MinusCircle size={28} className="mb-1" />
                      <span className="text-xs font-bold uppercase">N/A</span>
                    </button>
                  </div>

                  {/* Notes Input */}
                  <div className="flex-1">
                    <textarea
                      placeholder="Observações..."
                      value={item.notes}
                      onChange={e => handleCriteriaNotesChange(item.id, e.target.value)}
                      rows={3}
                      className="w-full p-3 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none text-base"
                    />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* AI Summary Section */}
        <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-indigo-900 flex items-center gap-2">
              <Bot size={24} /> Resumo e Conclusões
            </h3>
            <button
              type="button"
              onClick={handleGenerateSummary}
              disabled={isGeneratingAI}
              className="text-sm bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2 transition-all"
            >
              {isGeneratingAI ? <Loader2 className="animate-spin" size={16}/> : <Bot size={16}/>}
              {summary ? 'Regerar com IA' : 'Gerar Resumo IA'}
            </button>
          </div>
          <textarea
            value={summary}
            onChange={e => setSummary(e.target.value)}
            placeholder="Escreva um resumo ou utilize a IA para gerar com base nos critérios acima..."
            className="w-full p-4 bg-white text-black border border-indigo-200 rounded-lg h-40 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
        </div>

        {/* Signatures */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pb-12">

          <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
            <label className="block text-sm font-semibold text-gray-700 mb-2">Nome do Auditor</label>
            <input 
              type="text" 
              value={auditorName} 
              onChange={e => setAuditorName(e.target.value)}
              className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <SignaturePad 
              label="Assinatura do Auditor"
              onEnd={setAuditorSignature}
            />
          </div>

          <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
             <label className="block text-sm font-semibold text-gray-700 mb-2">Nome do Representante do Cliente</label>
             <input 
              type="text" 
              value={clientName} 
              onChange={e => setClientName(e.target.value)}
              className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded focus:ring-2 focus:ring-blue-500 outline-none"
            />
            <SignaturePad 
              label="Assinatura do Cliente"
              onEnd={setClientSignature}
            />
          </div>

        </div>

      </div>
    </form>
  );
};

export default ReportForm;

import React, { useState } from 'react';
import { 
  Users, 
  FileText, 
  Settings, 
  Plus, 
  ChevronRight, 
  Search,
  LayoutDashboard,
  Calendar,
  Briefcase,
  Edit2,
  Trash2,
  X,
  CheckSquare,
  Square
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';
import { MOCK_USERS, MOCK_CLIENTS, MOCK_REPORTS, REPORT_TEMPLATES } from './constants';
import { User, Client, Report, UserRole, ReportTypeKey } from './types';
import ReportForm from './components/ReportForm';

enum Screen {
  DASHBOARD = 'Dashboard',
  CLIENTS = 'Clientes',
  REPORTS = 'Relatórios',
  SETTINGS = 'Configurações'
}

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042'];

const App: React.FC = () => {
  // --- Global State ---
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[1]); // Default to Auditor
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.DASHBOARD);

  // Data State
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [reports, setReports] = useState<Report[]>(MOCK_REPORTS);

  // Client Management State
  const [isClientModalOpen, setIsClientModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null); // If null, it's adding new
  const [clientSearch, setClientSearch] = useState('');

  // Report Workflow State
  const [selectedClientForReport, setSelectedClientForReport] = useState<Client | null>(null);
  const [isReportTypeModalOpen, setIsReportTypeModalOpen] = useState(false);
  const [selectedTemplateKey, setSelectedTemplateKey] = useState<ReportTypeKey | null>(null);

  // Derived State
  const recentReports = reports.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 5);
  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
    c.nif?.includes(clientSearch)
  );

  // --- Actions: Clients ---

  const handleSaveClient = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const clientData: Client = {
      id: editingClient ? editingClient.id : `c-${Date.now()}`,
      name: formData.get('name') as string,
      nif: formData.get('nif') as string,
      address: formData.get('address') as string,
      contactPerson: formData.get('contactPerson') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      status: 'Ativo', // Default
      lastVisit: editingClient?.lastVisit || '-'
    };

    if (editingClient) {
      setClients(clients.map(c => c.id === clientData.id ? clientData : c));
    } else {
      setClients([...clients, clientData]);
    }
    setIsClientModalOpen(false);
    setEditingClient(null);
  };

  const handleDeleteClient = (id: string) => {
    if (confirm('Tem a certeza que deseja remover este cliente?')) {
      setClients(clients.filter(c => c.id !== id));
    }
  };

  const openEditClient = (client: Client) => {
    setEditingClient(client);
    setIsClientModalOpen(true);
  };

  const openAddClient = () => {
    setEditingClient(null);
    setIsClientModalOpen(true);
  };

  // --- Actions: Reports ---

  const initReportCreation = (client: Client) => {
    setSelectedClientForReport(client);
    setIsReportTypeModalOpen(true);
  };

  const selectReportType = (key: ReportTypeKey) => {
    setSelectedTemplateKey(key);
    setIsReportTypeModalOpen(false);
  };

  const handleSaveReport = (report: Report) => {
    setReports([report, ...reports]);
    // Update client last visit
    setClients(clients.map(c => c.id === report.clientId ? { ...c, lastVisit: report.date } : c));

    // Reset states
    setSelectedTemplateKey(null);
    setSelectedClientForReport(null);
    setCurrentScreen(Screen.REPORTS);
  };

  // --- Actions: Admin Settings ---
  const togglePermission = (userId: string, key: ReportTypeKey) => {
    if (currentUser.role !== UserRole.ADMIN) return;

    setUsers(users.map(u => {
      if (u.id !== userId) return u;
      const hasPermission = u.allowedTemplates.includes(key);
      const newPermissions = hasPermission
        ? u.allowedTemplates.filter(t => t !== key)
        : [...u.allowedTemplates, key];
      return { ...u, allowedTemplates: newPermissions };
    }));

    // Update current user if self-modified
    if (currentUser.id === userId) {
      const u = users.find(u => u.id === userId);
      if (u) {
        // Logic to toggle
        const hasPermission = u.allowedTemplates.includes(key);
        const newPermissions = hasPermission
            ? u.allowedTemplates.filter(t => t !== key)
            : [...u.allowedTemplates, key];
        setCurrentUser({ ...currentUser, allowedTemplates: newPermissions });
      }
    }
  };

