  // Helper Components
  const NavItem = ({ screen, icon: Icon }: { screen: Screen; icon: any }) => (
    <button
      onClick={() => {
        setCurrentScreen(screen);
        // Reset flows
        setSelectedClientForReport(null);
        setSelectedTemplateKey(null);
      }}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
        currentScreen === screen 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{screen}</span>
    </button>
  );

  // If creating report
  if (selectedClientForReport && selectedTemplateKey) {
    return (
      <ReportForm 
        client={selectedClientForReport} 
        auditor={currentUser} 
        template={REPORT_TEMPLATES[selectedTemplateKey]}
        onSave={handleSaveReport}
        onCancel={() => {
          setSelectedTemplateKey(null);
          setSelectedClientForReport(null);
        }}
      />
    );
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">

      {/* Sidebar */}
