          <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            <Briefcase className="text-blue-600" />
            AuditPro
          </h1>
        </div>

        <nav className="flex-1 px-4 space-y-2">
          <NavItem screen={Screen.DASHBOARD} icon={LayoutDashboard} />
          <NavItem screen={Screen.CLIENTS} icon={Users} />
          <NavItem screen={Screen.REPORTS} icon={FileText} />
          {currentUser.role === UserRole.ADMIN && (
            <NavItem screen={Screen.SETTINGS} icon={Settings} />
          )}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-xl mb-3">
            <img src={currentUser.avatar} alt="User" className="w-10 h-10 rounded-full bg-gray-200" />
            <div className="flex-1 overflow-hidden">
              <p className="text-sm font-bold text-gray-800 truncate">{currentUser.name}</p>
              <p className="text-xs text-gray-500 truncate">{currentUser.role}</p>
            </div>
          </div>
          <select 
            className="w-full text-xs p-2 border rounded bg-white text-black"
            value={currentUser.id}
            onChange={(e) => {
              const u = users.find(u => u.id === e.target.value);
              if (u) setCurrentUser(u);
            }}
          >
            {users.map(u => (
              <option key={u.id} value={u.id}>{u.name} ({u.role})</option>
            ))}
          </select>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Mobile Header */}
        <header className="bg-white border-b border-gray-200 p-4 md:hidden flex justify-between items-center z-10">
          <h1 className="text-lg font-bold text-gray-800">AuditPro</h1>
          <button className="p-2 bg-gray-100 rounded-full">
            <img src={currentUser.avatar} alt="User" className="w-8 h-8 rounded-full" />
          </button>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">

          {/* Dashboard View */}
          {currentScreen === Screen.DASHBOARD && (
            <div className="space-y-6">
