                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                  <p className="text-gray-500 text-sm">Total Clientes</p>
                  <h3 className="text-3xl font-bold text-gray-800 mt-2">{clients.length}</h3>
                </div>
