import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { Report, CompanySettings, Client } from '../types';

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;

  // --- HEADER ---
  doc.setFillColor(41, 128, 185); // Blue header
  doc.rect(0, 0, pageWidth, 40, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text(company.name, 14, 18);

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`${company.address} | NIF: ${company.nif}`, 14, 25);
  doc.text(`${company.email} | ${company.phone}`, 14, 30);

  doc.setFontSize(16);
  doc.text('RELATÓRIO DE INTERVENÇÃO', pageWidth - 14, 25, { align: 'right' });

  // --- INFO BLOCK ---
  let y = 50;

  doc.setTextColor(0, 0, 0);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text('DADOS DO CLIENTE', 14, y);
  doc.text('DADOS DA INTERVENÇÃO', pageWidth / 2 + 5, y);
  y += 5;

  doc.setDrawColor(200);
  doc.line(14, y, pageWidth - 14, y);
  y += 5;

  doc.setFont('helvetica', 'normal');
  // Client Column
  doc.text(`Cliente: ${client.name}`, 14, y);
  if (client.shopName) doc.text(`Loja: ${client.shopName}`, 14, y + 5);
  doc.text(`Morada: ${client.address}`, 14, y + 10);
  doc.text(`${client.postalCode} ${client.locality}, ${client.county}`, 14, y + 15);
  doc.text(`NIF: ${client.nif || 'N/A'}`, 14, y + 20);
  doc.text(`Responsável: ${report.clientSignerName}`, 14, y + 25);

  // Intervention Column
  const col2 = pageWidth / 2 + 5;
  doc.text(`Data: ${report.date}`, col2, y);
  doc.text(`Horário: ${report.startTime} - ${report.endTime}`, col2, y + 5);
  doc.text(`Técnico: ${report.auditorName}`, col2, y + 10);
  doc.text(`Tipo: ${report.typeName}`, col2, y + 15);
  if (report.contractNumber) doc.text(`Contrato: ${report.contractNumber}`, col2, y + 20);
  if (report.routeNumber) doc.text(`Rota: ${report.routeNumber}`, col2, y + 25);
  if (report.gpsLocation) doc.text(`GPS: ${report.gpsLocation.lat.toFixed(5)}, ${report.gpsLocation.lng.toFixed(5)}`, col2, y + 30);

  y += 40;

  // --- CRITERIA TABLE ---
  if (report.criteria && report.criteria.length > 0) {
    const tableData = report.criteria.map(c => [
      c.label,
      c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
      c.notes || ''
    ]);

    (doc as any).autoTable({
      startY: y,
      head: [['Critério de Avaliação', 'Estado', 'Observações']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [41, 128, 185] },
      columnStyles: {
        0: { cellWidth: 90 },
        1: { cellWidth: 20, halign: 'center' },
        2: { cellWidth: 'auto' }
      }
    });

    y = (doc as any).lastAutoTable.finalY + 15;
  }

  // --- SUMMARY / FREE TEXT ---
  doc.setFont('helvetica', 'bold');
  doc.text(report.typeKey === 'intervention_general' ? 'RELATÓRIO DA INTERVENÇÃO' : 'RESUMO / CONCLUSÕES', 14, y);
  y += 5;
  doc.setFont('helvetica', 'normal');
  const splitSummary = doc.splitTextToSize(report.summary || 'Sem observações.', pageWidth - 28);
  doc.text(splitSummary, 14, y);
  y += (splitSummary.length * 5) + 10;

  // --- CLIENT OBSERVATIONS ---
  if (report.clientObservations) {
    doc.setFont('helvetica', 'bold');
    doc.text('OBSERVAÇÕES DO CLIENTE', 14, y);
    y += 5;
    doc.setFont('helvetica', 'normal');
    const splitClientObs = doc.splitTextToSize(report.clientObservations, pageWidth - 28);
    doc.text(splitClientObs, 14, y);
    y += (splitClientObs.length * 5) + 10;
  }

  // --- SIGNATURES ---
  // Ensure we have space for signatures
  if (y > 250) {
    doc.addPage();
    y = 20;
  }

  y += 10;
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);

  // Auditor Sig
  doc.text('TÉCNICO RESPONSÁVEL', 14, y);
  if (report.auditorSignature) {
    doc.addImage(report.auditorSignature, 'PNG', 14, y + 2, 60, 25);
  }
  doc.text(report.auditorName, 14, y + 30);

  // Client Sig
  doc.text('RESPONSÁVEL CLIENTE', pageWidth / 2 + 5, y);
  if (report.clientSignature) {
    doc.addImage(report.clientSignature, 'PNG', pageWidth / 2 + 5, y + 2, 60, 25);
  }
  doc.text(report.clientSignerName, pageWidth / 2 + 5, y + 30);

  // --- FOOTER ---
  const pageCount = (doc as any).internal.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFontSize(8);
    doc.setTextColor(150);
    doc.text(`Gerado por AuditPro 360 - Página ${i} de ${pageCount}`, pageWidth / 2, doc.internal.pageSize.height - 10, { align: 'center' });
  }

  return doc;
};

import React, { useRef, useState, useEffect } from 'react';
import { Eraser } from 'lucide-react';

interface SignaturePadProps {
  label: string;
  onEnd: (dataUrl: string | null) => void;
  initialData?: string | null;
  disabled?: boolean;
}

const SignaturePad: React.FC<SignaturePadProps> = ({ label, onEnd, initialData, disabled = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [hasSignature, setHasSignature] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas && initialData) {
      const ctx = canvas.getContext('2d');
      const img = new Image();
      img.src = initialData;
      img.onload = () => {
        ctx?.drawImage(img, 0, 0);
        setHasSignature(true);
      };
    }
  }, [initialData]);

  // Updated Coordinate Logic for Better Precision
  const getCoordinates = (event: MouseEvent | TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();

    // Account for canvas scaling if CSS width != Attribute width
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    let clientX, clientY;

    if ((event as any).touches && (event as any).touches.length > 0) {
      clientX = (event as TouchEvent).touches[0].clientX;
      clientY = (event as TouchEvent).touches[0].clientY;
    } else {
      clientX = (event as MouseEvent).clientX;
      clientY = (event as MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    if (disabled) return;
    setIsDrawing(true);
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.lineWidth = 3; // Slightly thicker
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.strokeStyle = '#000000';

    const { x, y } = getCoordinates(e.nativeEvent as any);
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || disabled) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Prevent scrolling on touch devices
    if(e.type === 'touchmove') {
      // e.preventDefault() is handled by touch-action: none in CSS
    }

    const { x, y } = getCoordinates(e.nativeEvent as any);
    ctx.lineTo(x, y);
    ctx.stroke();
    setHasSignature(true);
  };

  const stopDrawing = () => {
    if (disabled) return;
    setIsDrawing(false);
    if (canvasRef.current && hasSignature) {
      onEnd(canvasRef.current.toDataURL());
    }
  };

  const clear = () => {
    if (disabled) return;
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      ctx?.clearRect(0, 0, canvas.width, canvas.height);
      setHasSignature(false);
      onEnd(null);
    }
  };

  return (
    <div className="flex flex-col gap-2 w-full">
      <div className="flex justify-between items-center">
        <label className="text-sm font-semibold text-gray-700">{label}</label>
        {!disabled && (
          <button 
            type="button"
            onClick={clear}
            className="text-xs flex items-center gap-1 text-red-600 hover:text-red-800"
          >
            <Eraser size={14} /> Limpar
          </button>
        )}
      </div>
      <div className={`border-2 border-dashed ${disabled ? 'bg-gray-100 border-gray-300' : 'bg-white border-gray-400'} rounded-lg overflow-hidden touch-none`}>
        <canvas
          ref={canvasRef}
          width={600} // Higher resolution
          height={250}
          className="w-full h-40 cursor-crosshair touch-none"
          style={{ touchAction: 'none' }}
          onMouseDown={startDrawing}
          onMouseMove={draw}
          onMouseUp={stopDrawing}
          onMouseLeave={stopDrawing}
          onTouchStart={startDrawing}
          onTouchMove={draw}
          onTouchEnd={stopDrawing}
        />
      </div>
      {!hasSignature && !disabled && (
        <p className="text-xs text-amber-600">Assinatura obrigatória</p>
      )}
    </div>
  );
};

export default SignaturePad;

import React, { useState } from 'react';
import { User } from '../types';
import { Lock } from 'lucide-react';

interface LoginScreenProps {
  users: User[];
  onLogin: (user: User) => void;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ users, onLogin }) => {
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  const handleNumClick = (num: string) => {
    if (pin.length < 6) {
      setPin(prev => prev + num);
      setError('');
    }
  };

  const handleBackspace = () => {
    setPin(prev => prev.slice(0, -1));
  };

  const handleSubmit = () => {
    if (!selectedUser) return;
    if (selectedUser.pin === pin) {
      onLogin(selectedUser);
    } else {
      setError('PIN Incorreto');
      setPin('');
    }
  };

  if (!selectedUser) {
    return (
      <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-4">
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md">
          <h1 className="text-2xl font-bold text-center mb-6 text-gray-800">AuditPro 360</h1>
          <p className="text-center text-gray-500 mb-6">Selecione o seu utilizador</p>
          <div className="grid grid-cols-2 gap-4">
            {users.map(u => (
              <button
                key={u.id}
                onClick={() => setSelectedUser(u)}
                className="flex flex-col items-center p-4 border rounded-xl hover:bg-blue-50 hover:border-blue-200 transition-all"
              >
                <div className="w-16 h-16 rounded-full bg-gray-200 overflow-hidden mb-2">
                  <img src={u.avatar} alt={u.name} className="w-full h-full object-cover" />
                </div>
                <span className="font-semibold text-gray-700">{u.name}</span>
                <span className="text-xs text-gray-500">{u.role}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-4">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-sm">
        <button onClick={() => { setSelectedUser(null); setPin(''); }} className="text-sm text-gray-500 mb-4 hover:underline">
          &larr; Voltar
        </button>
        <div className="flex flex-col items-center mb-6">
          <div className="w-20 h-20 rounded-full bg-gray-200 overflow-hidden mb-2">
            <img src={selectedUser.avatar} alt={selectedUser.name} className="w-full h-full object-cover" />
          </div>
          <h2 className="text-xl font-bold text-gray-800">{selectedUser.name}</h2>
          <p className="text-sm text-gray-500">Introduza o PIN de 6 dígitos</p>
        </div>

        <div className="flex justify-center gap-2 mb-6">
          {[...Array(6)].map((_, i) => (
            <div key={i} className={`w-4 h-4 rounded-full border ${i < pin.length ? 'bg-blue-600 border-blue-600' : 'bg-transparent border-gray-300'}`} />
          ))}
        </div>

        {error && <p className="text-red-500 text-center text-sm mb-4">{error}</p>}

        <div className="grid grid-cols-3 gap-4 mb-6">
          {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
            <button
              key={num}
              onClick={() => handleNumClick(num.toString())}
              className="w-full h-14 rounded-full bg-gray-50 text-xl font-bold text-gray-700 hover:bg-gray-100 active:bg-gray-200 transition-colors"
            >
              {num}
            </button>
          ))}
          <div />
          <button
            onClick={() => handleNumClick('0')}
            className="w-full h-14 rounded-full bg-gray-50 text-xl font-bold text-gray-700 hover:bg-gray-100 active:bg-gray-200 transition-colors"
          >
            0
          </button>
          <button
            onClick={handleBackspace}
            className="w-full h-14 rounded-full bg-red-50 text-red-600 flex items-center justify-center hover:bg-red-100 transition-colors"
          >
            ⌫
          </button>
        </div>

        <button
          onClick={handleSubmit}
          disabled={pin.length !== 6}
          className="w-full py-3 bg-blue-600 text-white rounded-lg font-bold text-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
        >
          Entrar
        </button>
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useEffect } from 'react';
import { Report, Client, User, AuditCriteria, ReportTemplate, CompanySettings } from '../types';
import SignaturePad from './SignaturePad';
import { generateReportSummary } from '../services/geminiService';
import { generatePDF } from '../services/pdfService';
import { Save, Bot, CheckCircle, AlertCircle, MinusCircle, Loader2, FileText, Download, Mail, MapPin } from 'lucide-react';

interface ReportFormProps {
  client: Client;
  auditor: User;
  template: ReportTemplate;
  companySettings: CompanySettings;
  onSave: (report: Report) => void;
  onCancel: () => void;
}

const ReportForm: React.FC<ReportFormProps> = ({ client, auditor, template, companySettings, onSave, onCancel }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState(new Date().toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));
  const [endTime, setEndTime] = useState(new Date(Date.now() + 3600000).toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' })); // +1 hour default

  const [contractNumber, setContractNumber] = useState('');
  const [routeNumber, setRouteNumber] = useState('');

  // Initialize criteria from template
  const [criteria, setCriteria] = useState<AuditCriteria[]>(
    template.defaultCriteria.map((c, idx) => ({
      id: `crit-${idx}`,
      label: c.label,
      status: null,
      notes: ''
    }))
  );

  const [summary, setSummary] = useState('');
  const [clientObservations, setClientObservations] = useState('');

  // Signature States
  const [auditorName, setAuditorName] = useState(auditor.name);
  const [auditorSignature, setAuditorSignature] = useState<string | null>(null);

  const [clientName, setClientName] = useState(client.contactPerson);
  const [clientSignature, setClientSignature] = useState<string | null>(null);

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [gpsCoords, setGpsCoords] = useState<{lat: number, lng: number} | undefined>(undefined);

  const handleCriteriaStatusChange = (id: string, status: AuditCriteria['status']) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, status } : c));
  };

  const handleCriteriaNotesChange = (id: string, notes: string) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, notes } : c));
  };

  const handleGenerateSummary = async () => {
    setIsGeneratingAI(true);
    const result = await generateReportSummary(client.name, template.label, criteria);
    setSummary(result);
    setIsGeneratingAI(false);
  };

  const handleFinish = async (action: 'save' | 'pdf' | 'email') => {
    if (!auditorSignature || !clientSignature) {
      alert("Ambas as assinaturas são obrigatórias.");
      return;
    }
    if (!auditorName.trim() || !clientName.trim()) {
      alert("Os nomes dos signatários são obrigatórios.");
      return;
    }

    if (!window.confirm("Deseja gravar o relatório? Após gravar não será possível efetuar alterações.")) {
      return;
    }

    // Capture GPS
    let location = undefined;
    if ("geolocation" in navigator) {
      try {
        const position = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        location = { lat: position.coords.latitude, lng: position.coords.longitude };
        setGpsCoords(location);
      } catch (e) {
        console.warn("Could not get GPS", e);
      }
    }

    const newReport: Report = {
      id: `r-${Date.now()}`,
      clientId: client.id,
      clientName: client.name,
      clientShopName: client.shopName,
      auditorId: auditor.id,
      auditorName: auditor.name, 
      date,
      startTime,
      endTime,
      contractNumber,
      routeNumber,
      typeKey: template.key,
      typeName: template.label,
      criteria,
      summary,
      clientObservations,
      auditorSignerName: auditorName,
      auditorSignature,
      clientSignerName: clientName,
      clientSignature,
      gpsLocation: location,
      status: 'Finalizado'
    };

    if (action === 'pdf' || action === 'email') {
      const doc = generatePDF(newReport, client, companySettings);

      if (action === 'pdf') {
        doc.save(`Relatorio_${client.name.replace(/\s+/g, '_')}_${date}.pdf`);
      } else {
        // Simulate Email
        const pdfBlob = doc.output('blob');
        const subject = encodeURIComponent(`Relatório de Intervenção - ${client.name}`);
        const body = encodeURIComponent(`Segue em anexo o relatório da intervenção realizada dia ${date}.\n\nCumprimentos,\n${companySettings.name}`);

        // We can't actually attach without backend, so we open mailto and download pdf
        window.open(`mailto:${client.email}?subject=${subject}&body=${body}`);
        doc.save(`Relatorio_${client.name}_${date}.pdf`); // Force download so user can attach
        alert("O cliente de email foi aberto. O PDF foi descarregado para que o possa anexar manualmente.");
      }
    }

    onSave(newReport);
  };

  const hasCriteria = criteria.length > 0;
  const isGeneralIntervention = template.key === 'intervention_general';

  return (
    <div className="flex flex-col h-full bg-gray-50 fixed inset-0 z-50 overflow-hidden">
      {/* Sticky Header */}
      <div className="bg-white border-b shadow-sm px-6 py-4 flex justify-between items-center shrink-0">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Novo Relatório</h2>
          <p className="text-sm font-semibold text-blue-600">{template.label}</p>
          <p className="text-xs text-gray-500">{client.name}</p>
        </div>
        <div className="flex gap-3">
          <button type="button" onClick={onCancel} className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg font-medium hover:bg-gray-200">
            Cancelar
          </button>

          <button onClick={() => handleFinish('email')} className="px-4 py-2 bg-indigo-100 text-indigo-700 rounded-lg font-medium hover:bg-indigo-200 flex items-center gap-2">
             <Mail size={18} /> Enviar
          </button>
           <button onClick={() => handleFinish('pdf')} className="px-4 py-2 bg-indigo-100 text-indigo-700 rounded-lg font-medium hover:bg-indigo-200 flex items-center gap-2">
             <Download size={18} /> PDF
          </button>

          <button onClick={() => handleFinish('save')} className="px-6 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200">
            <Save size={18} /> Finalizar
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 w-full mx-auto">
        {/* Full width container */}
        <div className="max-w-[1600px] mx-auto space-y-8">

          {/* Info Section */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Data</label>
                <input 
                  type="date" 
                  value={date} 
                  onChange={e => setDate(e.target.value)}
                  className="w-full p-3 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Início</label>
                <input 
                  type="time" 
                  value={startTime}
                  onChange={e => setStartTime(e.target.value)} 
                  className="w-full p-3 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Fim</label>
                <input 
