                    <p className="flex items-start gap-2"><MapPin size={16} className="mt-1 shrink-0"/> {viewingHistoryClient.address}, {viewingHistoryClient.postalCode} {viewingHistoryClient.locality}, {viewingHistoryClient.county}</p>
