                        <tr>
                          <td colSpan={4} className="px-6 py-8 text-center text-gray-500">
                            Ainda não existem relatórios para este cliente.
                          </td>
                        </tr>
                      ) : (
                        availableReports
                        .filter(r => r.clientId === viewingHistoryClient.id)
                        .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                        .map(report => (
                        <tr key={report.id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-4">
                             <p className="font-medium text-gray-900">{report.date}</p>
                             <p className="text-xs text-gray-500">{report.startTime} - {report.endTime}</p>
                          </td>
                          <td className="px-6 py-4">
                            <span className="px-3 py-1 bg-blue-50 text-blue-700 text-xs rounded-full font-medium border border-blue-100">
                              {report.typeName}
                            </span>
                            {report.order && <span className="text-[10px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded ml-1">Enc.</span>}
                          </td>
                          <td className="px-6 py-4 text-sm text-gray-600">{report.auditorName}</td>
                          <td className="px-6 py-4 text-right">
                             <div className="flex justify-end gap-2">
                                <button onClick={() => handleViewReport(report)} className="px-3 py-1.5 text-xs font-medium text-purple-700 bg-purple-50 border border-purple-200 rounded hover:bg-purple-100 flex items-center gap-1 shadow-sm">
                                  <Eye size={14} /> Ver
                                </button>
                                <button onClick={() => handleDownloadPDF(report)} className="px-3 py-1.5 text-xs font-medium text-gray-700 bg-white border border-gray-300 rounded hover:bg-gray-50 flex items-center gap-1 shadow-sm">
                                  <Download size={14} /> PDF
                                </button>
                                <button onClick={() => handleEmailReport(report)} className="px-3 py-1.5 text-xs font-medium text-indigo-700 bg-indigo-50 border border-indigo-200 rounded hover:bg-indigo-100 flex items-center gap-1 shadow-sm">
                                  <Mail size={14} /> Email
                                </button>
                             </div>
                          </td>
                        </tr>
                      )))}
                    </tbody>
                  </table>
                </div>
              </div>

            </div>
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

export enum UserRole {
  ADMIN = 'Administrador',
  COMERCIAL = 'Comercial',
  AUDITOR = 'Auditor',
  TECNICO = 'Técnico'
}

export type ReportTypeKey = 'visit_comercial' | 'audit_pool' | 'audit_haccp' | 'maint_prev' | 'safety_check' | 'pest_control' | 'intervention_general';

export interface User {
  id: string;
  name: string;
  role: UserRole;
  avatar?: string;
  pin: string; // 6 digit pin
  allowedTemplates: ReportTypeKey[]; // Access control
}

export interface Client {
  id: string;
  name: string;
  nif?: string; // Tax ID
  contactPerson: string;
  email: string;
  phone: string;

  // Address Fields
  address: string;
  postalCode: string;
  locality: string; // Localidade
  county: string;   // Concelho
  shopName?: string; // Nome da Loja (se aplicável)

  lastVisit?: string;
  visitFrequency?: number; // Frequency in days for alerts
  status: 'Ativo' | 'Inativo';

  // Access Control
  accountManagerId?: string; // ID of the commercial responsible for this client
}

export interface AuditCriteria {
  id: string;
  label: string;
  status: 'pass' | 'fail' | 'na' | null;
  notes: string;
}

export interface ReportTemplate {
  key: ReportTypeKey;
  label: string;
  defaultCriteria: { label: string }[];
}

export interface OrderItem {
  id: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  discount: number; // Percentage
  total: number;
}

export interface Order {
  items: OrderItem[];
  deliveryConditions: string;
  observations: string;
  totalValue: number;
}

export interface Report {
  id: string;
  clientId: string;
  clientName: string;
  clientShopName?: string;
  auditorId: string;
  auditorName: string;
  date: string;
  startTime: string;
  endTime: string;
  contractNumber?: string;
  routeNumber?: string;
  typeKey: ReportTypeKey;
  typeName: string;
  criteria: AuditCriteria[];
  summary: string;
  clientObservations?: string;

  // Order Data (Optional - usually for Commercial Visits)
  order?: Order;

  // Signatures
  auditorSignerName: string;
  auditorSignature: string | null;
  clientSignerName: string;
  clientSignature: string | null;

  // Metadata
  gpsLocation?: { lat: number; lng: number };
  status: 'Rascunho' | 'Finalizado';
}

export interface CompanySettings {
  name: string;
  nif: string;
  address: string;
  postalCode?: string;
  locality?: string;
  email: string;
  phone: string;
  website: string;
  logoUrl?: string;
}

