    // Client Info
    y += 15;

    // Commercial Name Header
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`Comercial: ${report.auditorName}`, margin, y);

    y += 10;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DADOS DO CLIENTE", margin, y);
    y += 5;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(client.name, margin, y);
    y += 4;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
    y += 4;
    doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
    y += 4;
    doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

    y += 10;

    // Order Table
    const orderData = report.order.items.map(item => [
        item.productName,
        item.quantity.toString(),
        `${item.unitPrice.toFixed(2)}€`,
        `${item.discount}%`,
        `${item.total.toFixed(2)}€`
    ]);

    autoTable(doc, {
        startY: y,
        head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
        body: orderData,
        theme: 'striped',
        styles: { fontSize: 8 },
        headStyles: { fillColor: COLORS.PRIMARY },
        columnStyles: {
            0: { cellWidth: 'auto' },
            1: { cellWidth: 15, halign: 'center' },
            2: { cellWidth: 25, halign: 'right' },
            3: { cellWidth: 15, halign: 'center' },
            4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
        },
        margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 5;

    // Total and Conditions
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
    y += 15;

    if (report.order.deliveryConditions) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Condições de Entrega:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.deliveryConditions, margin, y);
        y += 8;
    }

    if (report.order.observations) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Observações:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.observations, margin, y);
        y += 8;
    }

    // Signatures
    const sigY = pageHeight - 40;
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, sigY, margin + 60, sigY);
    doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

    doc.setFontSize(8);
    // Explicitly showing Commercial Name under signature line
    doc.text("O Comercial", margin, sigY + 5);
    doc.setFont('helvetica', 'bold');
    doc.text(report.auditorName, margin, sigY + 10);

    doc.setFont('helvetica', 'normal');
    doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

    return doc;
};

import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Report, CompanySettings, Client } from '../types';

// Constants for styling
const COLORS: { [key: string]: [number, number, number] } = {
  PRIMARY: [30, 58, 138], // Blue-900
  SECONDARY: [100, 116, 139], // Slate-500
  ACCENT: [241, 245, 249], // Slate-100 (Backgrounds)
  TEXT: [15, 23, 42], // Slate-900
  OK: [22, 163, 74], // Green-600
  NOK: [220, 38, 38], // Red-600
  NA: [148, 163, 184] // Slate-400
};

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  // Ensure jsPDF constructor works (ESM compatibility)
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.width;
  const pageHeight = doc.internal.pageSize.height;
  const margin = 14;
  const contentWidth = pageWidth - (margin * 2);

  // Helper: Draw Section Title
  const drawSectionTitle = (title: string, y: number) => {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(title.toUpperCase(), margin, y);
    doc.setDrawColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.setLineWidth(0.5);
    doc.line(margin, y + 1.5, margin + 40, y + 1.5); // Underline part
    return y + 6;
  };

  // Helper: Draw Field
  const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 80) => {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(label, x, y);

    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    // Handle long text wrapping
    const splitText = doc.splitTextToSize(value, maxWidth);
    doc.text(splitText, x, y + 4);

    return (splitText.length * 3.5) + 3; // Return height used
  };

  // --- 1. HEADER ---
  let y = 15;

  // Logo (Left)
  if (company.logoUrl) {
    try {
      doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
    } catch (e) {
      console.warn("Logo error", e);
    }
  }

  // Company Info (Right Aligned)
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(12);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text(company.name, pageWidth - margin, y, { align: 'right' });
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text(company.address, pageWidth - margin, y, { align: 'right' });
  y += 4;
  doc.text(`${company.postalCode || ''} ${company.locality || ''}`, pageWidth - margin, y, { align: 'right' }); 
  y += 4;
  doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });
  y += 4;
  doc.text(company.email, pageWidth - margin, y, { align: 'right' });

  // Document Title Bar
  y = 42;
  doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.rect(margin, y, contentWidth, 10, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.text("RELATÓRIO DE INTERVENÇÃO TÉCNICA", margin + 4, y + 6.5);

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);
  doc.text(`Nº ${report.id.replace('r-', '')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

  // --- 2. INFO GRID (Client & Intervention) ---
  y += 15;
  const boxHeight = 42;
  const colWidth = (contentWidth / 2) - 4;

  // Draw Background Boxes
  doc.setFillColor(COLORS.ACCENT[0], COLORS.ACCENT[1], COLORS.ACCENT[2]);
  doc.roundedRect(margin, y, colWidth, boxHeight, 2, 2, 'F'); // Client Box
  doc.roundedRect(margin + colWidth + 8, y, colWidth, boxHeight, 2, 2, 'F'); // Intervention Box

  // Client Data
  let cy = y + 6;
  const cx = margin + 4;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text("CLIENTE", cx, cy);
  cy += 6;

  cy += drawField("Nome / Empresa", client.name, cx, cy, colWidth - 8);
  cy += drawField("Localização", `${client.address}, ${client.locality}`, cx, cy, colWidth - 8);

  // Quick contact line
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text("Contacto:", cx, cy + 4);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
  doc.text(`${client.contactPerson} (${client.phone})`, cx + 18, cy + 4);

  // Intervention Data
  let iy = y + 6;
  const ix = margin + colWidth + 12;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text("DETALHES DO SERVIÇO", ix, iy);
  iy += 6;

  // Compact line for times
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text("Horário:", ix, iy);
  doc.text("Técnico:", ix + (colWidth/2), iy);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
  doc.text(`${report.startTime} - ${report.endTime}`, ix, iy + 4);
  doc.text(report.auditorName.split(' ')[0], ix + (colWidth/2), iy + 4);
  iy += 9;

  iy += drawField("Tipo de Serviço", report.typeName, ix, iy, colWidth - 8);
  if (report.contractNumber || report.routeNumber) {
    drawField("Contrato / Rota", `${report.contractNumber || '-'} / ${report.routeNumber || '-'}`, ix, iy, colWidth - 8);
  }

  y += boxHeight + 8;

  // --- 3. CRITERIA TABLE ---
  if (report.criteria && report.criteria.length > 0) {
    const tableData = report.criteria.map(c => [
      c.label,
      c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
      c.notes || ''
    ]);

    autoTable(doc, {
      startY: y,
      head: [['CRITÉRIO AVALIADO', 'ESTADO', 'OBSERVAÇÕES TÉCNICAS']],
      body: tableData,
      theme: 'plain', // Clean look
      styles: {
        fontSize: 7,
        cellPadding: 2,
        font: 'helvetica',
        textColor: COLORS.TEXT,
        lineColor: [226, 232, 240], // Slate-200
        lineWidth: 0.1,
      },
      headStyles: {
        fillColor: COLORS.ACCENT,
        textColor: COLORS.PRIMARY,
        fontStyle: 'bold',
        fontSize: 7,
      },
      columnStyles: {
        0: { cellWidth: 80, fontStyle: 'bold' },
        1: { cellWidth: 20, halign: 'center', fontStyle: 'bold' },
        2: { cellWidth: 'auto' }
      },
      didParseCell: function(data) {
        // Color coding for Status
        if (data.section === 'body' && data.column.index === 1) {
          const text = data.cell.text[0];
          if (text === 'OK') data.cell.styles.textColor = COLORS.OK;
          if (text === 'NOK') data.cell.styles.textColor = COLORS.NOK;
          if (text === 'N/A') data.cell.styles.textColor = COLORS.NA;
        }
        // Zebra striping manually for cleaner look
        if (data.section === 'body' && data.row.index % 2 === 1) {
           data.cell.styles.fillColor = [248, 250, 252]; // Slate-50
        }
      },
      margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 8;
  }

  // --- 3.5 ORDER TABLE (If exists) ---
  if (report.order && report.order.items.length > 0) {

    // Check if we need new page before order
    if (pageHeight - y < 60) {
        doc.addPage();
        y = 20;
    }

    drawSectionTitle("Nota de Encomenda", y);
    y += 5;

    const orderData = report.order.items.map(item => [
        item.productName,
        item.quantity.toString(),
        `${item.unitPrice.toFixed(2)}€`,
        `${item.discount}%`,
        `${item.total.toFixed(2)}€`
    ]);

    autoTable(doc, {
        startY: y,
        head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
        body: orderData,
        theme: 'plain',
        styles: {
            fontSize: 7,
            cellPadding: 2,
            font: 'helvetica',
            textColor: COLORS.TEXT,
            lineColor: [226, 232, 240],
            lineWidth: 0.1,
        },
        headStyles: {
            fillColor: COLORS.PRIMARY,
            textColor: [255, 255, 255],
            fontStyle: 'bold',
            fontSize: 7,
        },
        columnStyles: {
            0: { cellWidth: 'auto' },
            1: { cellWidth: 15, halign: 'center' },
            2: { cellWidth: 20, halign: 'right' },
            3: { cellWidth: 15, halign: 'center' },
            4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
        },
        margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 4;

    // Total Value
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
    y += 8;

    // Delivery Conditions & Obs
    if (report.order.deliveryConditions || report.order.observations) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(8);
        doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

        if (report.order.deliveryConditions) {
            doc.text("Condições de Entrega:", margin, y);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
            doc.text(report.order.deliveryConditions, margin + 35, y);
            y += 5;
        }

        if (report.order.observations) {
            doc.setFont('helvetica', 'bold');
            doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
            doc.text("Obs. Encomenda:", margin, y);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
            doc.text(report.order.observations, margin + 35, y);
            y += 5;
        }
    }
    y += 4;
  }

  // --- 4. OBSERVATIONS & SUMMARY ---

  // Check space for observations. If minimal space left, add page.
  if (pageHeight - y < 90) {
    doc.addPage();
    y = 20;
  }

  // Summary Box
  drawSectionTitle("Resumo e Conclusões", y);
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);

  const summaryText = report.summary || "Sem observações adicionais a registar.";
  const splitSummary = doc.splitTextToSize(summaryText, contentWidth);
  doc.text(splitSummary, margin, y);
  y += (splitSummary.length * 4) + 8;

  // Client Obs (if exists)
  if (report.clientObservations) {
    drawSectionTitle("Observações do Cliente", y);
    y += 5;
    const clientObsText = report.clientObservations;
    const splitClientObs = doc.splitTextToSize(clientObsText, contentWidth);
    doc.setFont('helvetica', 'italic');
    doc.text(splitClientObs, margin, y);
    doc.setFont('helvetica', 'normal');
    y += (splitClientObs.length * 4) + 8;
  }

  // --- 5. SIGNATURES (Anchored Bottom) ---

  // Only draw signatures if NOT a commercial visit
  if (report.typeKey !== 'visit_comercial') {

    // Calculate footer area height required (approx 45 units)
    const footerHeight = 45;
    let sigY = pageHeight - footerHeight - 10; // 10 padding from bottom edge

    // If current content overlaps signature area, push signatures to next page
    if (y > sigY) {
      doc.addPage();
      sigY = pageHeight - footerHeight - 10;
    }

    // Draw light separator line
    doc.setDrawColor(226, 232, 240);
    doc.line(margin, sigY, pageWidth - margin, sigY);
    sigY += 5;

    const sigBoxWidth = (contentWidth / 2) - 10;
    const sigBoxHeight = 35;

    // Auditor Signature Area
    const aX = margin;
    doc.setFontSize(7);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(report.order ? "COMERCIAL" : "TÉCNICO RESPONSÁVEL", aX, sigY + 3);

    if (report.auditorSignature) {
      try {
        doc.addImage(report.auditorSignature, 'PNG', aX, sigY + 5, 40, 18);
      } catch(e) { console.warn("Auditor signature error", e); }
    }
    doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.setLineWidth(0.1);
    doc.line(aX, sigY + 25, aX + sigBoxWidth, sigY + 25); // Signature Line

    doc.setFont('helvetica', 'bold');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(report.auditorName, aX, sigY + 29);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Assinado digitalmente", aX, sigY + 32);

    // Client Signature Area
    const cX = pageWidth - margin - sigBoxWidth;
    doc.setFontSize(7);
    doc.text("PELO CLIENTE", cX, sigY + 3);

    if (report.clientSignature) {
      try {
        doc.addImage(report.clientSignature, 'PNG', cX, sigY + 5, 40, 18);
      } catch(e) { console.warn("Client signature error", e); }
    }
    doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.line(cX, sigY + 25, cX + sigBoxWidth, sigY + 25); // Signature Line

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(7);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(report.clientSignerName, cX, sigY + 29);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Validado no local", cX, sigY + 32);
  } else {
    // If commercial visit, maybe just add a small footer note or nothing
    let noteY = pageHeight - 15;
    if (y > noteY) {
        doc.addPage();
        noteY = pageHeight - 15;
    }
    doc.setFontSize(7);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Relatório de visita comercial (não carece de assinatura).", margin, noteY);
  }

  // --- 6. FOOTER (Page Numbers) ---
  const pageCount = (doc as any).internal.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    const footerText = `AuditPro 360 | Processado informaticamente | Pág. ${i}/${pageCount}`;
    doc.text(footerText, pageWidth / 2, pageHeight - 5, { align: 'center' });
  }

  return doc;
};

// Function to generate ONLY the Order PDF
export const generateOrderPDF = (report: Report, client: Client, company: CompanySettings) => {
    if (!report.order) return generatePDF(report, client, company); // Fallback

    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const contentWidth = pageWidth - (margin * 2);

    let y = 15;

    // --- Header (Similar to main report but specific title) ---
    if (company.logoUrl) {
        try {
          doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
        } catch (e) {
          console.warn("Logo error", e);
        }
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(company.name, pageWidth - margin, y, { align: 'right' });
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(company.address, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });

    // Document Title Bar
    y = 42;
    doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.rect(margin, y, contentWidth, 10, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text("NOTA DE ENCOMENDA", margin + 4, y + 6.5);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(`Ref: ${report.id.replace('r-', 'enc-')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

    // Client Info
    y += 15;

    // Commercial Name Header
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`Comercial: ${report.auditorName}`, margin, y);

    y += 10;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DADOS DO CLIENTE", margin, y);
    y += 5;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(client.name, margin, y);
    y += 4;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
    y += 4;
    doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
    y += 4;
    doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

    y += 10;

    // Order Table
    const orderData = report.order.items.map(item => [
        item.productName,
        item.quantity.toString(),
        `${item.unitPrice.toFixed(2)}€`,
        `${item.discount}%`,
        `${item.total.toFixed(2)}€`
    ]);

    autoTable(doc, {
        startY: y,
        head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
        body: orderData,
        theme: 'striped',
        styles: { fontSize: 8 },
        headStyles: { 
            fillColor: COLORS.PRIMARY, 
            textColor: [255, 255, 255] 
        },
        columnStyles: {
            0: { cellWidth: 'auto' },
            1: { cellWidth: 15, halign: 'center' },
            2: { cellWidth: 25, halign: 'right' },
            3: { cellWidth: 15, halign: 'center' },
            4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
        },
        margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 5;

    // Total and Conditions
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
    y += 15;

    if (report.order.deliveryConditions) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Condições de Entrega:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.deliveryConditions, margin, y);
        y += 8;
    }

    if (report.order.observations) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Observações:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.observations, margin, y);
        y += 8;
    }

    // Signatures
    const sigY = pageHeight - 40;
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, sigY, margin + 60, sigY);
    doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

    doc.setFontSize(8);
    // Explicitly showing Commercial Name under signature line
    doc.text("O Comercial", margin, sigY + 5);
    doc.setFont('helvetica', 'bold');
    doc.text(report.auditorName, margin, sigY + 10);

    doc.setFont('helvetica', 'normal');
    doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

    return doc;
};

import { Report, CompanySettings, Client } from '../types';

// Declare globals for the script tags loaded in index.html
declare global {
  interface Window {
    jspdf: any;
  }
}

// Constants for styling
const COLORS: { [key: string]: [number, number, number] } = {
  PRIMARY: [30, 58, 138], // Blue-900
  SECONDARY: [100, 116, 139], // Slate-500
  ACCENT: [241, 245, 249], // Slate-100 (Backgrounds)
  TEXT: [15, 23, 42], // Slate-900
  OK: [22, 163, 74], // Green-600
  NOK: [220, 38, 38], // Red-600
  NA: [148, 163, 184] // Slate-400
};

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  // Access jsPDF from the global window object (loaded via script tag)
  if (!window.jspdf) {
    alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
    throw new Error("jsPDF not loaded");
  }

  const { jsPDF } = window.jspdf;
  const doc = new jsPDF();

  const pageWidth = doc.internal.pageSize.width;
  const pageHeight = doc.internal.pageSize.height;
  const margin = 14;
  const contentWidth = pageWidth - (margin * 2);

  // Helper: Draw Section Title
  const drawSectionTitle = (title: string, y: number) => {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(title.toUpperCase(), margin, y);
    doc.setDrawColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.setLineWidth(0.5);
    doc.line(margin, y + 1.5, margin + 40, y + 1.5); // Underline part
    return y + 6;
  };

  // Helper: Draw Field
  const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 80) => {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(label, x, y);

    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    // Handle long text wrapping
    const splitText = doc.splitTextToSize(value, maxWidth);
    doc.text(splitText, x, y + 4);

    return (splitText.length * 3.5) + 3; // Return height used
  };

  // --- 1. HEADER ---
  let y = 15;

  // Logo (Left)
  if (company.logoUrl) {
    try {
      doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
    } catch (e) {
      console.warn("Logo error", e);
    }
  }

  // Company Info (Right Aligned)
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(12);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text(company.name, pageWidth - margin, y, { align: 'right' });
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text(company.address, pageWidth - margin, y, { align: 'right' });
  y += 4;
  doc.text(`${company.postalCode || ''} ${company.locality || ''}`, pageWidth - margin, y, { align: 'right' }); 
  y += 4;
  doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });
  y += 4;
  doc.text(company.email, pageWidth - margin, y, { align: 'right' });

  // Document Title Bar
  y = 42;
  doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.rect(margin, y, contentWidth, 10, 'F');

  doc.setTextColor(255, 255, 255);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.text("RELATÓRIO DE INTERVENÇÃO TÉCNICA", margin + 4, y + 6.5);

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(9);
  doc.text(`Nº ${report.id.replace('r-', '')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

  // --- 2. INFO GRID (Client & Intervention) ---
  y += 15;
  const boxHeight = 42;
  const colWidth = (contentWidth / 2) - 4;

  // Draw Background Boxes
  doc.setFillColor(COLORS.ACCENT[0], COLORS.ACCENT[1], COLORS.ACCENT[2]);
  doc.roundedRect(margin, y, colWidth, boxHeight, 2, 2, 'F'); // Client Box
  doc.roundedRect(margin + colWidth + 8, y, colWidth, boxHeight, 2, 2, 'F'); // Intervention Box

  // Client Data
  let cy = y + 6;
  const cx = margin + 4;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text("CLIENTE", cx, cy);
  cy += 6;

  cy += drawField("Nome / Empresa", client.name, cx, cy, colWidth - 8);
  cy += drawField("Localização", `${client.address}, ${client.locality}`, cx, cy, colWidth - 8);

  // Quick contact line
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text("Contacto:", cx, cy + 4);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
  doc.text(`${client.contactPerson} (${client.phone})`, cx + 18, cy + 4);

  // Intervention Data
  let iy = y + 6;
  const ix = margin + colWidth + 12;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
  doc.text("DETALHES DO SERVIÇO", ix, iy);
  iy += 6;

  // Compact line for times
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
  doc.text("Horário:", ix, iy);
  doc.text("Técnico:", ix + (colWidth/2), iy);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
  doc.text(`${report.startTime} - ${report.endTime}`, ix, iy + 4);
  doc.text(report.auditorName.split(' ')[0], ix + (colWidth/2), iy + 4);
  iy += 9;

  iy += drawField("Tipo de Serviço", report.typeName, ix, iy, colWidth - 8);
  if (report.contractNumber || report.routeNumber) {
    drawField("Contrato / Rota", `${report.contractNumber || '-'} / ${report.routeNumber || '-'}`, ix, iy, colWidth - 8);
  }

  y += boxHeight + 8;

  // --- 3. CRITERIA TABLE ---
  if (report.criteria && report.criteria.length > 0) {
    const tableData = report.criteria.map(c => [
      c.label,
      c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
      c.notes || ''
    ]);

    // Use method attached to prototype by script tag
    (doc as any).autoTable({
      startY: y,
      head: [['CRITÉRIO AVALIADO', 'ESTADO', 'OBSERVAÇÕES TÉCNICAS']],
      body: tableData,
      theme: 'plain', // Clean look
      styles: {
        fontSize: 7,
        cellPadding: 2,
        font: 'helvetica',
        textColor: COLORS.TEXT,
        lineColor: [226, 232, 240], // Slate-200
        lineWidth: 0.1,
      },
      headStyles: {
        fillColor: COLORS.ACCENT,
        textColor: COLORS.PRIMARY,
        fontStyle: 'bold',
        fontSize: 7,
      },
      columnStyles: {
        0: { cellWidth: 80, fontStyle: 'bold' },
        1: { cellWidth: 20, halign: 'center', fontStyle: 'bold' },
        2: { cellWidth: 'auto' }
      },
      didParseCell: function(data: any) {
        // Color coding for Status
        if (data.section === 'body' && data.column.index === 1) {
          const text = data.cell.text[0];
          if (text === 'OK') data.cell.styles.textColor = COLORS.OK;
          if (text === 'NOK') data.cell.styles.textColor = COLORS.NOK;
          if (text === 'N/A') data.cell.styles.textColor = COLORS.NA;
        }
        // Zebra striping manually for cleaner look
        if (data.section === 'body' && data.row.index % 2 === 1) {
           data.cell.styles.fillColor = [248, 250, 252]; // Slate-50
        }
      },
      margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 8;
  }

  // --- 3.5 ORDER TABLE (If exists) ---
  if (report.order && report.order.items.length > 0) {

    // Check if we need new page before order
    if (pageHeight - y < 60) {
        doc.addPage();
        y = 20;
    }

    drawSectionTitle("Nota de Encomenda", y);
    y += 5;

    const orderData = report.order.items.map(item => [
        item.productName,
        item.quantity.toString(),
        `${item.unitPrice.toFixed(2)}€`,
        `${item.discount}%`,
        `${item.total.toFixed(2)}€`
    ]);

    (doc as any).autoTable({
        startY: y,
        head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
        body: orderData,
        theme: 'plain',
        styles: {
            fontSize: 7,
            cellPadding: 2,
            font: 'helvetica',
            textColor: COLORS.TEXT,
            lineColor: [226, 232, 240],
            lineWidth: 0.1,
        },
        headStyles: {
            fillColor: COLORS.PRIMARY,
            textColor: [255, 255, 255],
            fontStyle: 'bold',
            fontSize: 7,
        },
        columnStyles: {
            0: { cellWidth: 'auto' },
            1: { cellWidth: 15, halign: 'center' },
            2: { cellWidth: 20, halign: 'right' },
            3: { cellWidth: 15, halign: 'center' },
            4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
        },
        margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 4;

    // Total Value
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
    y += 8;

    // Delivery Conditions & Obs
    if (report.order.deliveryConditions || report.order.observations) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(8);
        doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

        if (report.order.deliveryConditions) {
            doc.text("Condições de Entrega:", margin, y);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
            doc.text(report.order.deliveryConditions, margin + 35, y);
            y += 5;
        }

        if (report.order.observations) {
            doc.setFont('helvetica', 'bold');
            doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
            doc.text("Obs. Encomenda:", margin, y);
            doc.setFont('helvetica', 'normal');
            doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
            doc.text(report.order.observations, margin + 35, y);
            y += 5;
        }
    }
    y += 4;
  }

  // --- 4. OBSERVATIONS & SUMMARY ---

  // Check space for observations. If minimal space left, add page.
  if (pageHeight - y < 90) {
    doc.addPage();
    y = 20;
  }

  // Summary Box
  drawSectionTitle("Resumo e Conclusões", y);
  y += 5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);

  const summaryText = report.summary || "Sem observações adicionais a registar.";
  const splitSummary = doc.splitTextToSize(summaryText, contentWidth);
  doc.text(splitSummary, margin, y);
  y += (splitSummary.length * 4) + 8;

  // Client Obs (if exists)
  if (report.clientObservations) {
    drawSectionTitle("Observações do Cliente", y);
    y += 5;
    const clientObsText = report.clientObservations;
    const splitClientObs = doc.splitTextToSize(clientObsText, contentWidth);
    doc.setFont('helvetica', 'italic');
    doc.text(splitClientObs, margin, y);
    doc.setFont('helvetica', 'normal');
    y += (splitClientObs.length * 4) + 8;
  }

  // --- 5. SIGNATURES (Anchored Bottom) ---

  // Only draw signatures if NOT a commercial visit
  if (report.typeKey !== 'visit_comercial') {

    // Calculate footer area height required (approx 45 units)
    const footerHeight = 45;
    let sigY = pageHeight - footerHeight - 10; // 10 padding from bottom edge

    // If current content overlaps signature area, push signatures to next page
    if (y > sigY) {
      doc.addPage();
      sigY = pageHeight - footerHeight - 10;
    }

    // Draw light separator line
    doc.setDrawColor(226, 232, 240);
    doc.line(margin, sigY, pageWidth - margin, sigY);
    sigY += 5;

    const sigBoxWidth = (contentWidth / 2) - 10;
    const sigBoxHeight = 35;

    // Auditor Signature Area
    const aX = margin;
    doc.setFontSize(7);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(report.order ? "COMERCIAL" : "TÉCNICO RESPONSÁVEL", aX, sigY + 3);

    if (report.auditorSignature) {
      try {
        doc.addImage(report.auditorSignature, 'PNG', aX, sigY + 5, 40, 18);
      } catch(e) { console.warn("Auditor signature error", e); }
    }
    doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.setLineWidth(0.1);
    doc.line(aX, sigY + 25, aX + sigBoxWidth, sigY + 25); // Signature Line

    doc.setFont('helvetica', 'bold');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(report.auditorName, aX, sigY + 29);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Assinado digitalmente", aX, sigY + 32);

    // Client Signature Area
    const cX = pageWidth - margin - sigBoxWidth;
    doc.setFontSize(7);
    doc.text("PELO CLIENTE", cX, sigY + 3);

    if (report.clientSignature) {
      try {
        doc.addImage(report.clientSignature, 'PNG', cX, sigY + 5, 40, 18);
      } catch(e) { console.warn("Client signature error", e); }
    }
    doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.line(cX, sigY + 25, cX + sigBoxWidth, sigY + 25); // Signature Line

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(7);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(report.clientSignerName, cX, sigY + 29);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Validado no local", cX, sigY + 32);
  } else {
    // If commercial visit, maybe just add a small footer note or nothing
    let noteY = pageHeight - 15;
    if (y > noteY) {
        doc.addPage();
        noteY = pageHeight - 15;
    }
    doc.setFontSize(7);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Relatório de visita comercial (não carece de assinatura).", margin, noteY);
  }

  // --- 6. FOOTER (Page Numbers) ---
  const pageCount = (doc as any).internal.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFontSize(6);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    const footerText = `AuditPro 360 | Processado informaticamente | Pág. ${i}/${pageCount}`;
    doc.text(footerText, pageWidth / 2, pageHeight - 5, { align: 'center' });
  }

  return doc;
};

// Function to generate ONLY the Order PDF
export const generateOrderPDF = (report: Report, client: Client, company: CompanySettings) => {
    // Access jsPDF from the global window object (loaded via script tag)
    if (!window.jspdf) {
        alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
        throw new Error("jsPDF not loaded");
    }

    if (!report.order) return generatePDF(report, client, company); // Fallback

    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const contentWidth = pageWidth - (margin * 2);

    let y = 15;

    // --- Header (Similar to main report but specific title) ---
    if (company.logoUrl) {
        try {
          doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
        } catch (e) {
          console.warn("Logo error", e);
        }
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(company.name, pageWidth - margin, y, { align: 'right' });
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(company.address, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });

    // Document Title Bar
    y = 42;
    doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.rect(margin, y, contentWidth, 10, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text("NOTA DE ENCOMENDA", margin + 4, y + 6.5);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(`Ref: ${report.id.replace('r-', 'enc-')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

    // Client Info
    y += 15;

    // Commercial Name Header
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`Comercial: ${report.auditorName}`, margin, y);

    y += 10;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(10);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DADOS DO CLIENTE", margin, y);
    y += 5;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(client.name, margin, y);
    y += 4;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
    y += 4;
    doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
    y += 4;
    doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

    y += 10;

    // Order Table
    const orderData = report.order.items.map(item => [
        item.productName,
        item.quantity.toString(),
        `${item.unitPrice.toFixed(2)}€`,
        `${item.discount}%`,
        `${item.total.toFixed(2)}€`
    ]);

    (doc as any).autoTable({
        startY: y,
        head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
        body: orderData,
        theme: 'striped',
        styles: { fontSize: 8 },
        headStyles: { 
            fillColor: COLORS.PRIMARY, 
            textColor: [255, 255, 255] 
        },
        columnStyles: {
            0: { cellWidth: 'auto' },
            1: { cellWidth: 15, halign: 'center' },
            2: { cellWidth: 25, halign: 'right' },
            3: { cellWidth: 15, halign: 'center' },
            4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
        },
        margin: { left: margin, right: margin }
    });

    y = (doc as any).lastAutoTable.finalY + 5;

    // Total and Conditions
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
    y += 15;

    if (report.order.deliveryConditions) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Condições de Entrega:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.deliveryConditions, margin, y);
        y += 8;
    }

    if (report.order.observations) {
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(9);
        doc.text("Observações:", margin, y);
        y += 4;
        doc.setFont('helvetica', 'normal');
        doc.text(report.order.observations, margin, y);
        y += 8;
    }

    // Signatures
    const sigY = pageHeight - 40;
    doc.setDrawColor(200, 200, 200);
    doc.line(margin, sigY, margin + 60, sigY);
    doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

    doc.setFontSize(8);
    // Explicitly showing Commercial Name under signature line
    doc.text("O Comercial", margin, sigY + 5);
    doc.setFont('helvetica', 'bold');
    doc.text(report.auditorName, margin, sigY + 10);

    doc.setFont('helvetica', 'normal');
    doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

    return doc;
};

import { Report, CompanySettings, Client } from '../types';

// Declare globals for the script tags loaded in index.html
declare global {
  interface Window {
    jspdf: any;
    jsPDF: any; // Shim global
  }
}

// Constants for styling
const COLORS: { [key: string]: [number, number, number] } = {
  PRIMARY: [30, 58, 138], // Blue-900
  SECONDARY: [100, 116, 139], // Slate-500
  ACCENT: [241, 245, 249], // Slate-100 (Backgrounds)
  TEXT: [15, 23, 42], // Slate-900
  OK: [22, 163, 74], // Green-600
  NOK: [220, 38, 38], // Red-600
  NA: [148, 163, 184] // Slate-400
};

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  try {
    // Access jsPDF from the global window object (loaded via script tag)
    if (!window.jspdf) {
      alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
      throw new Error("jsPDF not loaded");
    }

    const jsPDF = window.jspdf.jsPDF;
    const doc = new jsPDF();

    // Verify AutoTable Plugin
    if (typeof (doc as any).autoTable !== 'function') {
       alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
       throw new Error("AutoTable plugin missing");
    }

    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const contentWidth = pageWidth - (margin * 2);

    // Helper: Draw Section Title
    const drawSectionTitle = (title: string, y: number) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(title.toUpperCase(), margin, y);
      doc.setDrawColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.setLineWidth(0.5);
      doc.line(margin, y + 1.5, margin + 40, y + 1.5); // Underline part
      return y + 6;
    };

    // Helper: Draw Field
    const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 80) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(label, x, y);

      doc.setFont('helvetica', 'normal');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      // Handle long text wrapping
      const splitText = doc.splitTextToSize(value, maxWidth);
      doc.text(splitText, x, y + 4);

      return (splitText.length * 3.5) + 3; // Return height used
    };

    // --- 1. HEADER ---
    let y = 15;

    // Logo (Left)
    if (company.logoUrl) {
      try {
        doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
      } catch (e) {
        console.warn("Logo error", e);
      }
    }

    // Company Info (Right Aligned)
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(company.name, pageWidth - margin, y, { align: 'right' });
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(company.address, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(`${company.postalCode || ''} ${company.locality || ''}`, pageWidth - margin, y, { align: 'right' }); 
    y += 4;
    doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(company.email, pageWidth - margin, y, { align: 'right' });

    // Document Title Bar
    y = 42;
    doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.rect(margin, y, contentWidth, 10, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text("RELATÓRIO DE INTERVENÇÃO TÉCNICA", margin + 4, y + 6.5);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(`Nº ${report.id.replace('r-', '')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

    // --- 2. INFO GRID (Client & Intervention) ---
    y += 15;
    const boxHeight = 42;
    const colWidth = (contentWidth / 2) - 4;

    // Draw Background Boxes
    doc.setFillColor(COLORS.ACCENT[0], COLORS.ACCENT[1], COLORS.ACCENT[2]);
    doc.roundedRect(margin, y, colWidth, boxHeight, 2, 2, 'F'); // Client Box
    doc.roundedRect(margin + colWidth + 8, y, colWidth, boxHeight, 2, 2, 'F'); // Intervention Box

    // Client Data
    let cy = y + 6;
    const cx = margin + 4;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("CLIENTE", cx, cy);
    cy += 6;

    cy += drawField("Nome / Empresa", client.name, cx, cy, colWidth - 8);
    cy += drawField("Localização", `${client.address}, ${client.locality}`, cx, cy, colWidth - 8);

    // Quick contact line
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Contacto:", cx, cy + 4);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${client.contactPerson} (${client.phone})`, cx + 18, cy + 4);

    // Intervention Data
    let iy = y + 6;
    const ix = margin + colWidth + 12;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DETALHES DO SERVIÇO", ix, iy);
    iy += 6;

    // Compact line for times
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Horário:", ix, iy);
    doc.text("Técnico:", ix + (colWidth/2), iy);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${report.startTime} - ${report.endTime}`, ix, iy + 4);
    doc.text(report.auditorName.split(' ')[0], ix + (colWidth/2), iy + 4);
    iy += 9;

    iy += drawField("Tipo de Serviço", report.typeName, ix, iy, colWidth - 8);
    if (report.contractNumber || report.routeNumber) {
      drawField("Contrato / Rota", `${report.contractNumber || '-'} / ${report.routeNumber || '-'}`, ix, iy, colWidth - 8);
    }

    y += boxHeight + 8;

    // --- 3. CRITERIA TABLE ---
    if (report.criteria && report.criteria.length > 0) {
      const tableData = report.criteria.map(c => [
        c.label,
        c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
        c.notes || ''
      ]);

      // Use method attached to prototype by script tag
      (doc as any).autoTable({
        startY: y,
        head: [['CRITÉRIO AVALIADO', 'ESTADO', 'OBSERVAÇÕES TÉCNICAS']],
        body: tableData,
        theme: 'plain', // Clean look
        styles: {
          fontSize: 7,
          cellPadding: 2,
          font: 'helvetica',
          textColor: COLORS.TEXT,
          lineColor: [226, 232, 240], // Slate-200
          lineWidth: 0.1,
        },
        headStyles: {
          fillColor: COLORS.ACCENT,
          textColor: COLORS.PRIMARY,
          fontStyle: 'bold',
          fontSize: 7,
        },
        columnStyles: {
          0: { cellWidth: 80, fontStyle: 'bold' },
          1: { cellWidth: 20, halign: 'center', fontStyle: 'bold' },
          2: { cellWidth: 'auto' }
        },
        didParseCell: function(data: any) {
          // Color coding for Status
          if (data.section === 'body' && data.column.index === 1) {
            const text = data.cell.text[0];
            if (text === 'OK') data.cell.styles.textColor = COLORS.OK;
            if (text === 'NOK') data.cell.styles.textColor = COLORS.NOK;
            if (text === 'N/A') data.cell.styles.textColor = COLORS.NA;
          }
          // Zebra striping manually for cleaner look
          if (data.section === 'body' && data.row.index % 2 === 1) {
             data.cell.styles.fillColor = [248, 250, 252]; // Slate-50
          }
        },
        margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 8;
    }

    // --- 3.5 ORDER TABLE (If exists) ---
    if (report.order && report.order.items.length > 0) {

      // Check if we need new page before order
      if (pageHeight - y < 60) {
          doc.addPage();
          y = 20;
      }

      drawSectionTitle("Nota de Encomenda", y);
      y += 5;

      const orderData = report.order.items.map(item => [
          item.productName,
          item.quantity.toString(),
          `${item.unitPrice.toFixed(2)}€`,
          `${item.discount}%`,
          `${item.total.toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'plain',
          styles: {
              fontSize: 7,
              cellPadding: 2,
              font: 'helvetica',
              textColor: COLORS.TEXT,
              lineColor: [226, 232, 240],
              lineWidth: 0.1,
          },
          headStyles: {
              fillColor: COLORS.PRIMARY,
              textColor: [255, 255, 255],
              fontStyle: 'bold',
              fontSize: 7,
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 20, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 4;

      // Total Value
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 8;

      // Delivery Conditions & Obs
      if (report.order.deliveryConditions || report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(8);
          doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

          if (report.order.deliveryConditions) {
              doc.text("Condições de Entrega:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.deliveryConditions, margin + 35, y);
              y += 5;
          }

          if (report.order.observations) {
              doc.setFont('helvetica', 'bold');
              doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
              doc.text("Obs. Encomenda:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.observations, margin + 35, y);
              y += 5;
          }
      }
      y += 4;
    }

    // --- 4. OBSERVATIONS & SUMMARY ---

    // Check space for observations. If minimal space left, add page.
    if (pageHeight - y < 90) {
      doc.addPage();
      y = 20;
    }

    // Summary Box
    drawSectionTitle("Resumo e Conclusões", y);
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);

    const summaryText = report.summary || "Sem observações adicionais a registar.";
    const splitSummary = doc.splitTextToSize(summaryText, contentWidth);
    doc.text(splitSummary, margin, y);
    y += (splitSummary.length * 4) + 8;

    // Client Obs (if exists)
    if (report.clientObservations) {
      drawSectionTitle("Observações do Cliente", y);
      y += 5;
      const clientObsText = report.clientObservations;
      const splitClientObs = doc.splitTextToSize(clientObsText, contentWidth);
      doc.setFont('helvetica', 'italic');
      doc.text(splitClientObs, margin, y);
      doc.setFont('helvetica', 'normal');
      y += (splitClientObs.length * 4) + 8;
    }

    // --- 5. SIGNATURES (Anchored Bottom) ---

    // Only draw signatures if NOT a commercial visit
    if (report.typeKey !== 'visit_comercial') {

      // Calculate footer area height required (approx 45 units)
      const footerHeight = 45;
      let sigY = pageHeight - footerHeight - 10; // 10 padding from bottom edge

      // If current content overlaps signature area, push signatures to next page
      if (y > sigY) {
        doc.addPage();
        sigY = pageHeight - footerHeight - 10;
      }

      // Draw light separator line
      doc.setDrawColor(226, 232, 240);
      doc.line(margin, sigY, pageWidth - margin, sigY);
      sigY += 5;

      const sigBoxWidth = (contentWidth / 2) - 10;
      const sigBoxHeight = 35;

      // Auditor Signature Area
      const aX = margin;
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(report.order ? "COMERCIAL" : "TÉCNICO RESPONSÁVEL", aX, sigY + 3);

      if (report.auditorSignature) {
        try {
          doc.addImage(report.auditorSignature, 'PNG', aX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Auditor signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.setLineWidth(0.1);
      doc.line(aX, sigY + 25, aX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.auditorName, aX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Assinado digitalmente", aX, sigY + 32);

      // Client Signature Area
      const cX = pageWidth - margin - sigBoxWidth;
      doc.setFontSize(7);
      doc.text("PELO CLIENTE", cX, sigY + 3);

      if (report.clientSignature) {
        try {
          doc.addImage(report.clientSignature, 'PNG', cX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Client signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.line(cX, sigY + 25, cX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(7);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.clientSignerName, cX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Validado no local", cX, sigY + 32);
    } else {
      // If commercial visit, maybe just add a small footer note or nothing
      let noteY = pageHeight - 15;
      if (y > noteY) {
          doc.addPage();
          noteY = pageHeight - 15;
      }
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Relatório de visita comercial (não carece de assinatura).", margin, noteY);
    }

    // --- 6. FOOTER (Page Numbers) ---
    const pageCount = (doc as any).internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      const footerText = `AuditPro 360 | Processado informaticamente | Pág. ${i}/${pageCount}`;
      doc.text(footerText, pageWidth / 2, pageHeight - 5, { align: 'center' });
    }

    return doc;

  } catch (err) {
    console.error("Critical PDF Generation Error", err);
    alert(`Erro ao gerar PDF: ${(err as Error).message}`);
    throw err;
  }
};

// Function to generate ONLY the Order PDF
export const generateOrderPDF = (report: Report, client: Client, company: CompanySettings) => {
    try {
      // Access jsPDF from the global window object (loaded via script tag)
      if (!window.jspdf) {
          alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
          throw new Error("jsPDF not loaded");
      }

      if (!report.order) return generatePDF(report, client, company); // Fallback

      const jsPDF = window.jspdf.jsPDF;
      const doc = new jsPDF();

      // Verify AutoTable Plugin
      if (typeof (doc as any).autoTable !== 'function') {
        alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
        throw new Error("AutoTable plugin missing");
      }

      const pageWidth = doc.internal.pageSize.width;
      const pageHeight = doc.internal.pageSize.height;
      const margin = 14;
      const contentWidth = pageWidth - (margin * 2);

      let y = 15;

      // --- Header (Similar to main report but specific title) ---
      if (company.logoUrl) {
          try {
            doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
          } catch (e) {
            console.warn("Logo error", e);
          }
      }

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(company.name, pageWidth - margin, y, { align: 'right' });
      y += 5;

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(company.address, pageWidth - margin, y, { align: 'right' });
      y += 4;
      doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });

      // Document Title Bar
      y = 42;
      doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.rect(margin, y, contentWidth, 10, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.text("NOTA DE ENCOMENDA", margin + 4, y + 6.5);

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      doc.text(`Ref: ${report.id.replace('r-', 'enc-')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

      // Client Info
      y += 15;

      // Commercial Name Header
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(`Comercial: ${report.auditorName}`, margin, y);

      y += 10;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text("DADOS DO CLIENTE", margin, y);
      y += 5;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(client.name, margin, y);
      y += 4;
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
      y += 4;
      doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
      y += 4;
      doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

      y += 10;

      // Order Table
      const orderData = report.order.items.map(item => [
          item.productName,
          item.quantity.toString(),
          `${item.unitPrice.toFixed(2)}€`,
          `${item.discount}%`,
          `${item.total.toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'striped',
          styles: { fontSize: 8 },
          headStyles: { 
              fillColor: COLORS.PRIMARY, 
              textColor: [255, 255, 255] 
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 25, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 5;

      // Total and Conditions
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 15;

      if (report.order.deliveryConditions) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Condições de Entrega:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.deliveryConditions, margin, y);
          y += 8;
      }

      if (report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Observações:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.observations, margin, y);
          y += 8;
      }

      // Signatures
      const sigY = pageHeight - 40;
      doc.setDrawColor(200, 200, 200);
      doc.line(margin, sigY, margin + 60, sigY);
      doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

      doc.setFontSize(8);
      // Explicitly showing Commercial Name under signature line
      doc.text("O Comercial", margin, sigY + 5);
      doc.setFont('helvetica', 'bold');
      doc.text(report.auditorName, margin, sigY + 10);

      doc.setFont('helvetica', 'normal');
      doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

      return doc;
    } catch (err) {
      console.error("Critical Order PDF Generation Error", err);
      alert(`Erro ao gerar PDF de Encomenda: ${(err as Error).message}`);
      throw err;
    }
};

import React, { useState, useEffect } from 'react';
import { Report, Client, User, AuditCriteria, ReportTemplate, CompanySettings, OrderItem } from '../types';
import SignaturePad from './SignaturePad';
import { generatePDF, generateOrderPDF } from '../services/pdfService';
import { Save, CheckCircle, AlertCircle, MinusCircle, FileText, Download, Mail, MapPin, X, ShoppingCart, Plus, Trash2, ExternalLink } from 'lucide-react';

interface ReportFormProps {
  client: Client;
  auditor: User;
  template: ReportTemplate;
  companySettings: CompanySettings;
  onSave: (report: Report) => void;
  onCancel: () => void;
  initialReport?: Report; // Added for editing
  readOnly?: boolean; // New prop for viewing mode
}

const ReportForm: React.FC<ReportFormProps> = ({ client, auditor, template, companySettings, onSave, onCancel, initialReport, readOnly = false }) => {
  const [date, setDate] = useState(initialReport?.date || new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState(initialReport?.startTime || new Date().toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));
  const [endTime, setEndTime] = useState(initialReport?.endTime || new Date(Date.now() + 3600000).toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));

  const [contractNumber, setContractNumber] = useState(initialReport?.contractNumber || '');
  const [routeNumber, setRouteNumber] = useState(initialReport?.routeNumber || '');

  // Initialize criteria: from initialReport if editing/viewing, otherwise from template
  const [criteria, setCriteria] = useState<AuditCriteria[]>(
    initialReport 
      ? initialReport.criteria 
      : template.defaultCriteria.map((c, idx) => ({
          id: `crit-${idx}`,
          label: c.label,
          status: null,
          notes: ''
        }))
  );

  const [summary, setSummary] = useState(initialReport?.summary || '');
  const [clientObservations, setClientObservations] = useState(initialReport?.clientObservations || '');

  // --- ORDER STATE ---
  const [orderItems, setOrderItems] = useState<OrderItem[]>(initialReport?.order?.items || []);
  const [orderDeliveryConditions, setOrderDeliveryConditions] = useState(initialReport?.order?.deliveryConditions || '');
  const [orderObservations, setOrderObservations] = useState(initialReport?.order?.observations || '');
  const [orderTotal, setOrderTotal] = useState(initialReport?.order?.totalValue || 0);

  // Recalculate total when items change
  useEffect(() => {
    const total = orderItems.reduce((acc, item) => acc + item.total, 0);
    setOrderTotal(total);
  }, [orderItems]);

  // Signature States
  const [auditorName, setAuditorName] = useState(initialReport?.auditorSignerName || auditor.name);
  const [auditorSignature, setAuditorSignature] = useState<string | null>(initialReport?.auditorSignature || null);

  const [clientName, setClientName] = useState(initialReport?.clientSignerName || client.contactPerson);
  const [clientSignature, setClientSignature] = useState<string | null>(initialReport?.clientSignature || null);

  const [gpsCoords, setGpsCoords] = useState<{lat: number, lng: number} | undefined>(initialReport?.gpsLocation);

  const isCommercialVisit = template.key === 'visit_comercial';
  const hasCriteria = criteria.length > 0;
  const isGeneralIntervention = template.key === 'intervention_general';

  const handleCriteriaStatusChange = (id: string, status: AuditCriteria['status']) => {
    if (readOnly) return;
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, status } : c));
  };

  const handleCriteriaNotesChange = (id: string, notes: string) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, notes } : c));
  };

  // --- Order Logic ---
  const addOrderItem = () => {
      const newItem: OrderItem = {
          id: `item-${Date.now()}`,
          productName: '',
          quantity: 1,
          unitPrice: 0,
          discount: 0,
          total: 0
      };
      setOrderItems([...orderItems, newItem]);
  };

  const updateOrderItem = (id: string, field: keyof OrderItem, value: any) => {
      const updatedItems = orderItems.map(item => {
          if (item.id === id) {
              // Ensure numeric fields are actually numbers
              let finalValue = value;
              if (['quantity', 'unitPrice', 'discount'].includes(field)) {
                  finalValue = value === '' ? 0 : parseFloat(value);
              }

              const updated = { ...item, [field]: finalValue };

              // Recalculate line total using valid numbers
              const qty = Number(updated.quantity);
              const price = Number(updated.unitPrice);
              const disc = Number(updated.discount);

              updated.total = (qty * price) * (1 - disc / 100);

              return updated;
          }
          return item;
      });
      setOrderItems(updatedItems);
  };

  const removeOrderItem = (id: string) => {
      setOrderItems(orderItems.filter(i => i.id !== id));
  };

  const handleFinish = async (action: 'save' | 'pdf' | 'email' | 'order_pdf') => {
    // Basic validation only if saving
    if (action === 'save') {
      // Validate signatures ONLY if NOT a commercial visit
      if (!isCommercialVisit) {
        if (!auditorSignature || !clientSignature) {
          alert("Ambas as assinaturas são obrigatórias para este tipo de relatório.");
          return;
        }
        if (!auditorName.trim() || !clientName.trim()) {
          alert("Os nomes dos signatários são obrigatórios.");
          return;
        }
      }

      if (!window.confirm("Deseja gravar o relatório?")) {
        return;
      }
    }

    // Capture GPS logic (skip if readOnly or just exporting PDF)
    let location = gpsCoords;
    if (action === 'save' && !readOnly && !location && "geolocation" in navigator) {
      try {
        const position = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        location = { lat: position.coords.latitude, lng: position.coords.longitude };
        setGpsCoords(location);
      } catch (e) {
        console.warn("Could not get GPS", e);
      }
    }

    // Construct data object
    const reportData: Report = {
      id: initialReport?.id || `r-${Date.now()}`,
      clientId: client.id,
      clientName: client.name,
      clientShopName: client.shopName,
      auditorId: auditor.id,
      auditorName: auditor.name, 
      date,
      startTime,
      endTime,
      contractNumber,
      routeNumber,
      typeKey: template.key,
      typeName: template.label,
      criteria,
      summary,
      clientObservations,
      auditorSignerName: auditorName,
      auditorSignature,
      clientSignerName: clientName,
      clientSignature,
      gpsLocation: location,
      status: 'Finalizado',
      // Attach order if it exists
      order: orderItems.length > 0 ? {
          items: orderItems,
          deliveryConditions: orderDeliveryConditions,
          observations: orderObservations,
          totalValue: orderTotal
      } : undefined
    };

    if (action === 'pdf' || action === 'email') {
      const doc = generatePDF(reportData, client, companySettings);

      if (action === 'pdf') {
        doc.save(`Relatorio_${client.name.replace(/\s+/g, '_')}_${date}.pdf`);
      } else {
        const subject = encodeURIComponent(`Relatório de Intervenção - ${client.name}`);
        const body = encodeURIComponent(`Segue em anexo o relatório da intervenção realizada dia ${date}.\n\nCumprimentos,\n${companySettings.name}`);
        window.open(`mailto:${client.email}?subject=${subject}&body=${body}`);
        doc.save(`Relatorio_${client.name}_${date}.pdf`); 
        alert("O cliente de email foi aberto.");
      }
    }

    if (action === 'order_pdf') {
        const doc = generateOrderPDF(reportData, client, companySettings);
        doc.save(`Encomenda_${client.name.replace(/\s+/g, '_')}_${date}.pdf`);
    }

    if (action === 'save') {
      onSave(reportData);
    }
  };

  // Title logic
  let title = 'Novo Relatório';
  if (initialReport) title = readOnly ? 'Visualizar Relatório' : 'Editar Relatório';

  return (
    <div className="flex flex-col h-full bg-gray-50 fixed inset-0 z-50 overflow-hidden">
      {/* Sticky Header */}
      <div className="bg-white border-b shadow-sm px-4 md:px-6 py-4 flex justify-between items-center shrink-0 z-20">
        <div className="overflow-hidden mr-4">
          <h2 className="text-lg md:text-xl font-bold text-gray-800 truncate">{title}</h2>
          <p className="text-xs md:text-sm font-semibold text-blue-600 truncate">{template.label}</p>
        </div>
        <div className="flex gap-2">
          <button type="button" onClick={onCancel} className="px-3 py-2 text-gray-700 bg-gray-100 rounded-lg font-medium hover:bg-gray-200 text-sm flex items-center gap-2">
            {readOnly ? <X size={16}/> : null}
            {readOnly ? 'Fechar' : 'Cancelar'}
          </button>

          <button onClick={() => handleFinish('email')} className="hidden md:flex px-3 py-2 bg-indigo-100 text-indigo-700 rounded-lg font-medium hover:bg-indigo-200 items-center gap-2 text-sm">
             <Mail size={16} /> Enviar
          </button>

          {/* Export Options */}
          <div className="hidden md:flex gap-1">
               <button onClick={() => handleFinish('pdf')} className="px-3 py-2 bg-indigo-100 text-indigo-700 rounded-l-lg font-medium hover:bg-indigo-200 items-center gap-2 text-sm flex border-r border-indigo-200">
                <Download size={16} /> PDF Relatório
              </button>
              {isCommercialVisit && orderItems.length > 0 && (
                <button onClick={() => handleFinish('order_pdf')} className="px-3 py-2 bg-emerald-100 text-emerald-700 rounded-r-lg font-medium hover:bg-emerald-200 items-center gap-2 text-sm flex" title="PDF apenas da Encomenda">
                    <ShoppingCart size={16} /> PDF Enc.
                </button>
              )}
          </div>

          {!readOnly && (
            <button onClick={() => handleFinish('save')} className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200 text-sm">
              <Save size={16} /> <span className="hidden sm:inline">Finalizar</span>
            </button>
          )}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-6 w-full mx-auto">
        <div className="max-w-[1200px] mx-auto space-y-6 pb-20">

          {/* Info Section */}
          <div className="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100">
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Data</label>
                <input 
                  type="date" 
                  value={date} 
                  disabled={readOnly}
                  onChange={e => setDate(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Início</label>
                <input 
                  type="time" 
                  value={startTime}
                  disabled={readOnly}
                  onChange={e => setStartTime(e.target.value)} 
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Fim</label>
                <input 
                  type="time" 
                  value={endTime}
                  disabled={readOnly}
                  onChange={e => setEndTime(e.target.value)} 
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">GPS</label>
                 {gpsCoords ? (
                    <button 
                      type="button"
                      onClick={() => window.open(`https://www.google.com/maps/search/?api=1&query=${gpsCoords.lat},${gpsCoords.lng}`, '_blank')}
                      className="w-full p-2 bg-green-50 text-green-700 border border-green-200 rounded-lg flex items-center gap-2 truncate hover:bg-green-100 transition-colors"
                      title="Clique para ver no mapa"
                    >
                      <MapPin size={16} />
                      <span className="text-xs font-medium">Ver Mapa</span>
                      <ExternalLink size={12} className="opacity-50" />
                    </button>
                 ) : (
                   <div className="w-full p-2 bg-gray-50 text-gray-400 border border-gray-200 rounded-lg flex items-center gap-2 truncate">
                      <MapPin size={16} />
                      <span className="text-xs">Não capturado</span>
                   </div>
                 )}
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Nº Contrato</label>
                <input 
                  type="text" 
                  placeholder="Ex: 12345/24"
                  value={contractNumber} 
                  disabled={readOnly}
                  onChange={e => setContractNumber(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Nº Rota</label>
                <input 
                  type="text" 
                  placeholder="Ex: R-01"
                  value={routeNumber} 
                  disabled={readOnly}
                  onChange={e => setRouteNumber(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
            </div>
          </div>

          {/* Criteria Evaluation */}
          {hasCriteria && (
            <div className="space-y-4">
              <h3 className="text-lg font-bold text-gray-800 px-2">Grelha de Avaliação</h3>
              <div className="grid grid-cols-1 gap-4">
                {criteria.map((item) => (
                  <div key={item.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <p className="font-semibold text-gray-900 mb-3 text-lg">{item.label}</p>

                    {/* Tablet Optimized Buttons: Full width Grid */}
                    <div className="grid grid-cols-3 gap-2 mb-3 h-14">
                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'pass')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'pass' 
                            ? 'bg-green-600 border-green-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'pass' ? 'hover:bg-green-50' : ''} ${readOnly && item.status !== 'pass' ? 'opacity-30' : ''}`}
                      >
                        <CheckCircle size={24} className={item.status === 'pass' ? 'mr-2' : ''} />
                        {item.status === 'pass' && <span className="font-bold">OK</span>}
                      </button>

                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'fail')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'fail' 
                            ? 'bg-red-600 border-red-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'fail' ? 'hover:bg-red-50' : ''} ${readOnly && item.status !== 'fail' ? 'opacity-30' : ''}`}
                      >
                        <AlertCircle size={24} className={item.status === 'fail' ? 'mr-2' : ''} />
                         {item.status === 'fail' && <span className="font-bold">NOK</span>}
                      </button>

                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'na')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'na' 
                            ? 'bg-gray-600 border-gray-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'na' ? 'hover:bg-gray-100' : ''} ${readOnly && item.status !== 'na' ? 'opacity-30' : ''}`}
                      >
                        <MinusCircle size={24} className={item.status === 'na' ? 'mr-2' : ''} />
                         {item.status === 'na' && <span className="font-bold">N/A</span>}
                      </button>
                    </div>

                    {/* Notes */}
                    <textarea
                      placeholder="Observações..."
                      value={item.notes}
                      disabled={readOnly}
                      onChange={e => handleCriteriaNotesChange(item.id, e.target.value)}
                      rows={1}
                      className="w-full p-3 bg-white text-black border-b border-gray-300 focus:bg-white focus:border-blue-500 outline-none transition-colors text-base rounded-lg disabled:opacity-70"
                    />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* COMMERCIAL VISIT - ORDER SECTION */}
          {isCommercialVisit && (
              <div className="space-y-4">
                  <div className="flex justify-between items-center px-2">
                    <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                        <ShoppingCart size={20} className="text-emerald-600" /> Nova Encomenda
                    </h3>
                    {!readOnly && (
                        <button onClick={addOrderItem} className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-sm flex items-center gap-1 hover:bg-emerald-700">
                            <Plus size={16} /> Adicionar Produto
                        </button>
                    )}
                  </div>

                  <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                      <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 border-b border-gray-200">
                                <tr>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-1/3">Produto</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-20">Qtd</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-24">Preço (€)</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-20">Desc.%</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase text-right">Total</th>
                                    {!readOnly && <th className="px-4 py-3 w-10"></th>}
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {orderItems.map((item) => (
                                    <tr key={item.id}>
                                        <td className="p-2">
                                            <input 
                                                className="w-full p-2 border rounded bg-white text-gray-900"
                                                placeholder="Descrição do produto"
                                                value={item.productName}
                                                onChange={(e) => updateOrderItem(item.id, 'productName', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                            <input 
                                                type="number"
                                                min="1"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-center"
                                                value={item.quantity}
                                                onChange={(e) => updateOrderItem(item.id, 'quantity', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                            <input 
                                                type="number"
                                                min="0"
                                                step="0.01"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-right"
                                                value={item.unitPrice}
                                                onChange={(e) => updateOrderItem(item.id, 'unitPrice', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                             <input 
                                                type="number"
                                                min="0"
                                                max="100"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-center"
                                                value={item.discount}
                                                onChange={(e) => updateOrderItem(item.id, 'discount', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2 text-right font-bold text-gray-800">
                                            {item.total.toFixed(2)}€
                                        </td>
                                        {!readOnly && (
                                            <td className="p-2 text-center">
                                                <button onClick={() => removeOrderItem(item.id)} className="text-red-500 hover:text-red-700">
                                                    <Trash2 size={18} />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                ))}
                                {orderItems.length === 0 && (
                                    <tr>
                                        <td colSpan={6} className="p-4 text-center text-gray-400 text-sm">
                                            Nenhum produto adicionado à encomenda.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                            <tfoot className="bg-gray-50 font-bold">
                                <tr>
                                    <td colSpan={4} className="px-4 py-3 text-right text-gray-700">Valor Total:</td>
                                    <td className="px-4 py-3 text-right text-emerald-700 text-lg">{orderTotal.toFixed(2)}€</td>
                                    {!readOnly && <td></td>}
                                </tr>
                            </tfoot>
                        </table>
                      </div>

                      <div className="p-4 bg-emerald-50 border-t border-emerald-100 grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-xs font-bold text-emerald-800 uppercase mb-1">Condições de Entrega</label>
                              <input 
                                value={orderDeliveryConditions}
                                onChange={(e) => setOrderDeliveryConditions(e.target.value)}
                                disabled={readOnly}
                                className="w-full p-2 border border-emerald-200 rounded bg-white text-gray-900"
                                placeholder="Ex: Entrega em 48h, Portes incluídos..."
                              />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-emerald-800 uppercase mb-1">Observações da Encomenda</label>
                              <input 
                                value={orderObservations}
                                onChange={(e) => setOrderObservations(e.target.value)}
                                disabled={readOnly}
                                className="w-full p-2 border border-emerald-200 rounded bg-white text-gray-900"
                                placeholder="Notas internas ou para faturação..."
                              />
                          </div>
                      </div>
                  </div>
              </div>
          )}

          {/* Main Report / Summary Section */}
          <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100">
            <h3 className="text-lg font-semibold text-indigo-900 mb-3 flex items-center gap-2">
              <FileText size={20} /> {isGeneralIntervention ? 'Relatório da Intervenção' : 'Resumo e Conclusões'}
            </h3>
            <textarea
              value={summary}
              disabled={readOnly}
              onChange={e => setSummary(e.target.value)}
              placeholder={isGeneralIntervention ? "Descreva detalhadamente a intervenção realizada..." : "Escreva um resumo e conclusões..."}
              className={`w-full p-4 bg-white text-black border border-indigo-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm ${isGeneralIntervention ? 'h-64' : 'h-32'} disabled:bg-gray-100 disabled:text-gray-700`}
            />
          </div>

          {/* Client Observations */}
          <div className="bg-amber-50 p-6 rounded-xl border border-amber-100">
            <h3 className="text-lg font-semibold text-amber-900 mb-3">Observações do Cliente</h3>
            <textarea
              value={clientObservations}
              disabled={readOnly}
              onChange={e => setClientObservations(e.target.value)}
              placeholder="Registe aqui quaisquer observações ou comentários do cliente..."
              className="w-full p-4 bg-white text-black border border-amber-200 rounded-lg h-24 outline-none focus:ring-2 focus:ring-amber-500 shadow-sm disabled:bg-gray-100 disabled:text-gray-700"
            />
          </div>

          {/* Signatures - HIDE FOR COMMERCIAL VISITS */}
          {!isCommercialVisit && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

              <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Técnico (Auditor)</label>
                <input 
                  type="text" 
                  value={auditorName} 
                  disabled={readOnly}
                  onChange={e => setAuditorName(e.target.value)}
                  className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded outline-none disabled:bg-gray-100"
                />
                <SignaturePad 
                  label="Assinatura"
                  onEnd={setAuditorSignature}
                  initialData={auditorSignature}
                  disabled={readOnly}
                />
              </div>

              <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                 <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Cliente</label>
                 <input 
                  type="text" 
                  value={clientName} 
                  disabled={readOnly}
                  onChange={e => setClientName(e.target.value)}
                  className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded outline-none disabled:bg-gray-100"
                />
                <SignaturePad 
                  label="Assinatura"
                  onEnd={setClientSignature}
                  initialData={clientSignature}
                  disabled={readOnly}
                />
              </div>

            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default ReportForm;

import { Report, CompanySettings, Client } from '../types';

// Declare globals for the script tags loaded in index.html
declare global {
  interface Window {
    jspdf: any;
    jsPDF: any; // Shim global
  }
}

// Constants for styling
const COLORS: { [key: string]: [number, number, number] } = {
  PRIMARY: [30, 58, 138], // Blue-900
  SECONDARY: [100, 116, 139], // Slate-500
  ACCENT: [241, 245, 249], // Slate-100 (Backgrounds)
  TEXT: [15, 23, 42], // Slate-900
  OK: [22, 163, 74], // Green-600
  NOK: [220, 38, 38], // Red-600
  NA: [148, 163, 184] // Slate-400
};

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  try {
    // Access jsPDF from the global window object (loaded via script tag)
    if (!window.jspdf) {
      alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
      throw new Error("jsPDF not loaded");
    }

    const jsPDF = window.jspdf.jsPDF;
    const doc = new jsPDF();

    // Verify AutoTable Plugin
    if (typeof (doc as any).autoTable !== 'function') {
       alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
       throw new Error("AutoTable plugin missing");
    }

    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const contentWidth = pageWidth - (margin * 2);

    // Helper: Draw Section Title
    const drawSectionTitle = (title: string, y: number) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(title.toUpperCase(), margin, y);
      doc.setDrawColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.setLineWidth(0.5);
      doc.line(margin, y + 1.5, margin + 40, y + 1.5); // Underline part
      return y + 6;
    };

    // Helper: Draw Field
    const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 80) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(label, x, y);

      doc.setFont('helvetica', 'normal');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      // Handle long text wrapping
      const splitText = doc.splitTextToSize(value, maxWidth);
      doc.text(splitText, x, y + 4);

      return (splitText.length * 3.5) + 3; // Return height used
    };

    // --- 1. HEADER ---
    let y = 15;

    // Logo (Left)
    if (company.logoUrl) {
      try {
        doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
      } catch (e) {
        console.warn("Logo error", e);
      }
    }

    // Company Info (Right Aligned)
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(company.name, pageWidth - margin, y, { align: 'right' });
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(company.address, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(`${company.postalCode || ''} ${company.locality || ''}`, pageWidth - margin, y, { align: 'right' }); 
    y += 4;
    doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(company.email, pageWidth - margin, y, { align: 'right' });

    // Document Title Bar
    y = 42;
    doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.rect(margin, y, contentWidth, 10, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text("RELATÓRIO DE INTERVENÇÃO TÉCNICA", margin + 4, y + 6.5);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(`Nº ${report.id.replace('r-', '')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

    // --- 2. INFO GRID (Client & Intervention) ---
    y += 15;
    const boxHeight = 42;
    const colWidth = (contentWidth / 2) - 4;

    // Draw Background Boxes
    doc.setFillColor(COLORS.ACCENT[0], COLORS.ACCENT[1], COLORS.ACCENT[2]);
    doc.roundedRect(margin, y, colWidth, boxHeight, 2, 2, 'F'); // Client Box
    doc.roundedRect(margin + colWidth + 8, y, colWidth, boxHeight, 2, 2, 'F'); // Intervention Box

    // Client Data
    let cy = y + 6;
    const cx = margin + 4;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("CLIENTE", cx, cy);
    cy += 6;

    cy += drawField("Nome / Empresa", client.name, cx, cy, colWidth - 8);
    cy += drawField("Localização", `${client.address}, ${client.locality}`, cx, cy, colWidth - 8);

    // Quick contact line
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Contacto:", cx, cy + 4);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${client.contactPerson} (${client.phone})`, cx + 18, cy + 4);

    // Intervention Data
    let iy = y + 6;
    const ix = margin + colWidth + 12;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DETALHES DO SERVIÇO", ix, iy);
    iy += 6;

    // Compact line for times
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Horário:", ix, iy);
    doc.text("Técnico:", ix + (colWidth/2), iy);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${report.startTime} - ${report.endTime}`, ix, iy + 4);
    doc.text(report.auditorName.split(' ')[0], ix + (colWidth/2), iy + 4);
    iy += 9;

    iy += drawField("Tipo de Serviço", report.typeName, ix, iy, colWidth - 8);
    if (report.contractNumber || report.routeNumber) {
      drawField("Contrato / Rota", `${report.contractNumber || '-'} / ${report.routeNumber || '-'}`, ix, iy, colWidth - 8);
    }

    y += boxHeight + 8;

    // --- 3. CRITERIA TABLE ---
    if (report.criteria && report.criteria.length > 0) {
      const tableData = report.criteria.map(c => [
        c.label,
        c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
        c.notes || ''
      ]);

      // Use method attached to prototype by script tag
      (doc as any).autoTable({
        startY: y,
        head: [['CRITÉRIO AVALIADO', 'ESTADO', 'OBSERVAÇÕES TÉCNICAS']],
        body: tableData,
        theme: 'plain', // Clean look
        styles: {
          fontSize: 7,
          cellPadding: 2,
          font: 'helvetica',
          textColor: COLORS.TEXT,
          lineColor: [226, 232, 240], // Slate-200
          lineWidth: 0.1,
        },
        headStyles: {
          fillColor: COLORS.ACCENT,
          textColor: COLORS.PRIMARY,
          fontStyle: 'bold',
          fontSize: 7,
        },
        columnStyles: {
          0: { cellWidth: 80, fontStyle: 'bold' },
          1: { cellWidth: 20, halign: 'center', fontStyle: 'bold' },
          2: { cellWidth: 'auto' }
        },
        didParseCell: function(data: any) {
          // Color coding for Status
          if (data.section === 'body' && data.column.index === 1) {
            const text = data.cell.text[0];
            if (text === 'OK') data.cell.styles.textColor = COLORS.OK;
            if (text === 'NOK') data.cell.styles.textColor = COLORS.NOK;
            if (text === 'N/A') data.cell.styles.textColor = COLORS.NA;
          }
          // Zebra striping manually for cleaner look
          if (data.section === 'body' && data.row.index % 2 === 1) {
             data.cell.styles.fillColor = [248, 250, 252]; // Slate-50
          }
        },
        margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 8;
    }

    // --- 3.5 ORDER TABLE (If exists) ---
    if (report.order && report.order.items.length > 0) {

      // Check if we need new page before order
      if (pageHeight - y < 60) {
          doc.addPage();
          y = 20;
      }

      drawSectionTitle("Nota de Encomenda", y);
      y += 5;

      const orderData = report.order.items.map(item => [
          item.productName,
          String(item.quantity),
          `${Number(item.unitPrice).toFixed(2)}€`,
          `${item.discount}%`,
          `${Number(item.total).toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'plain',
          styles: {
              fontSize: 7,
              cellPadding: 2,
              font: 'helvetica',
              textColor: COLORS.TEXT,
              lineColor: [226, 232, 240],
              lineWidth: 0.1,
          },
          headStyles: {
              fillColor: COLORS.PRIMARY,
              textColor: [255, 255, 255],
              fontStyle: 'bold',
              fontSize: 7,
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 20, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 4;

      // Total Value
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 8;

      // Delivery Conditions & Obs
      if (report.order.deliveryConditions || report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(8);
          doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

          if (report.order.deliveryConditions) {
              doc.text("Condições de Entrega:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.deliveryConditions, margin + 35, y);
              y += 5;
          }

          if (report.order.observations) {
              doc.setFont('helvetica', 'bold');
              doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
              doc.text("Obs. Encomenda:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.observations, margin + 35, y);
              y += 5;
          }
      }
      y += 4;
    }

    // --- 4. OBSERVATIONS & SUMMARY ---

    // Check space for observations. If minimal space left, add page.
    if (pageHeight - y < 90) {
      doc.addPage();
      y = 20;
    }

    // Summary Box
    drawSectionTitle("Resumo e Conclusões", y);
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);

    const summaryText = report.summary || "Sem observações adicionais a registar.";
    const splitSummary = doc.splitTextToSize(summaryText, contentWidth);
    doc.text(splitSummary, margin, y);
    y += (splitSummary.length * 4) + 8;

    // Client Obs (if exists)
    if (report.clientObservations) {
      drawSectionTitle("Observações do Cliente", y);
      y += 5;
      const clientObsText = report.clientObservations;
      const splitClientObs = doc.splitTextToSize(clientObsText, contentWidth);
      doc.setFont('helvetica', 'italic');
      doc.text(splitClientObs, margin, y);
      doc.setFont('helvetica', 'normal');
      y += (splitClientObs.length * 4) + 8;
    }

    // --- 5. SIGNATURES (Anchored Bottom) ---

    // Only draw signatures if NOT a commercial visit
    if (report.typeKey !== 'visit_comercial') {

      // Calculate footer area height required (approx 45 units)
      const footerHeight = 45;
      let sigY = pageHeight - footerHeight - 10; // 10 padding from bottom edge

      // If current content overlaps signature area, push signatures to next page
      if (y > sigY) {
        doc.addPage();
        sigY = pageHeight - footerHeight - 10;
      }

      // Draw light separator line
      doc.setDrawColor(226, 232, 240);
      doc.line(margin, sigY, pageWidth - margin, sigY);
      sigY += 5;

      const sigBoxWidth = (contentWidth / 2) - 10;
      const sigBoxHeight = 35;

      // Auditor Signature Area
      const aX = margin;
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(report.order ? "COMERCIAL" : "TÉCNICO RESPONSÁVEL", aX, sigY + 3);

      if (report.auditorSignature) {
        try {
          doc.addImage(report.auditorSignature, 'PNG', aX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Auditor signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.setLineWidth(0.1);
      doc.line(aX, sigY + 25, aX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.auditorName, aX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Assinado digitalmente", aX, sigY + 32);

      // Client Signature Area
      const cX = pageWidth - margin - sigBoxWidth;
      doc.setFontSize(7);
      doc.text("PELO CLIENTE", cX, sigY + 3);

      if (report.clientSignature) {
        try {
          doc.addImage(report.clientSignature, 'PNG', cX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Client signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.line(cX, sigY + 25, cX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(7);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.clientSignerName, cX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Validado no local", cX, sigY + 32);
    } else {
      // If commercial visit, maybe just add a small footer note or nothing
      let noteY = pageHeight - 15;
      if (y > noteY) {
          doc.addPage();
          noteY = pageHeight - 15;
      }
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Relatório de visita comercial (não carece de assinatura).", margin, noteY);
    }

    // --- 6. FOOTER (Page Numbers) ---
    const pageCount = (doc as any).internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      const footerText = `AuditPro 360 | Processado informaticamente | Pág. ${i}/${pageCount}`;
      doc.text(footerText, pageWidth / 2, pageHeight - 5, { align: 'center' });
    }

    return doc;

  } catch (err) {
    console.error("Critical PDF Generation Error", err);
    alert(`Erro ao gerar PDF: ${(err as Error).message}`);
    throw err;
  }
};

// Function to generate ONLY the Order PDF
export const generateOrderPDF = (report: Report, client: Client, company: CompanySettings) => {
    try {
      // Access jsPDF from the global window object (loaded via script tag)
      if (!window.jspdf) {
          alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
          throw new Error("jsPDF not loaded");
      }

      if (!report.order) return generatePDF(report, client, company); // Fallback

      const jsPDF = window.jspdf.jsPDF;
      const doc = new jsPDF();

      // Verify AutoTable Plugin
      if (typeof (doc as any).autoTable !== 'function') {
        alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
        throw new Error("AutoTable plugin missing");
      }

      const pageWidth = doc.internal.pageSize.width;
      const pageHeight = doc.internal.pageSize.height;
      const margin = 14;
      const contentWidth = pageWidth - (margin * 2);

      let y = 15;

      // --- Header (Similar to main report but specific title) ---
      if (company.logoUrl) {
          try {
            doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
          } catch (e) {
            console.warn("Logo error", e);
          }
      }

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(company.name, pageWidth - margin, y, { align: 'right' });
      y += 5;

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(company.address, pageWidth - margin, y, { align: 'right' });
      y += 4;
      doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });

      // Document Title Bar
      y = 42;
      doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.rect(margin, y, contentWidth, 10, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.text("NOTA DE ENCOMENDA", margin + 4, y + 6.5);

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      doc.text(`Ref: ${report.id.replace('r-', 'enc-')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

      // Client Info
      y += 15;

      // Commercial Name Header
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(`Comercial: ${report.auditorName}`, margin, y);

      y += 10;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text("DADOS DO CLIENTE", margin, y);
      y += 5;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(client.name, margin, y);
      y += 4;
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
      y += 4;
      doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
      y += 4;
      doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

      y += 10;

      // Order Table
      const orderData = report.order.items.map(item => [
          item.productName,
          String(item.quantity),
          `${Number(item.unitPrice).toFixed(2)}€`,
          `${item.discount}%`,
          `${Number(item.total).toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'striped',
          styles: { fontSize: 8 },
          headStyles: { 
              fillColor: COLORS.PRIMARY, 
              textColor: [255, 255, 255] 
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 25, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 5;

      // Total and Conditions
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.text(`Valor Total: ${report.order.totalValue.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 15;

      if (report.order.deliveryConditions) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Condições de Entrega:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.deliveryConditions, margin, y);
          y += 8;
      }

      if (report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Observações:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.observations, margin, y);
          y += 8;
      }

      // Signatures
      const sigY = pageHeight - 40;
      doc.setDrawColor(200, 200, 200);
      doc.line(margin, sigY, margin + 60, sigY);
      doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

      doc.setFontSize(8);
      // Explicitly showing Commercial Name under signature line
      doc.text("O Comercial", margin, sigY + 5);
      doc.setFont('helvetica', 'bold');
      doc.text(report.auditorName, margin, sigY + 10);

      doc.setFont('helvetica', 'normal');
      doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

      return doc;
    } catch (err) {
      console.error("Critical Order PDF Generation Error", err);
      alert(`Erro ao gerar PDF de Encomenda: ${(err as Error).message}`);
      throw err;
    }
};

import React, { useState, useEffect } from 'react';
import { Report, Client, User, AuditCriteria, ReportTemplate, CompanySettings, OrderItem } from '../types';
import SignaturePad from './SignaturePad';
import { generatePDF, generateOrderPDF } from '../services/pdfService';
import { Save, CheckCircle, AlertCircle, MinusCircle, FileText, Download, Mail, MapPin, X, ShoppingCart, Plus, Trash2, ExternalLink } from 'lucide-react';

interface ReportFormProps {
  client: Client;
  auditor: User;
  template: ReportTemplate;
  companySettings: CompanySettings;
  onSave: (report: Report) => void;
  onCancel: () => void;
  initialReport?: Report; // Added for editing
  readOnly?: boolean; // New prop for viewing mode
}

const ReportForm: React.FC<ReportFormProps> = ({ client, auditor, template, companySettings, onSave, onCancel, initialReport, readOnly = false }) => {
  const [date, setDate] = useState(initialReport?.date || new Date().toISOString().split('T')[0]);
  const [startTime, setStartTime] = useState(initialReport?.startTime || new Date().toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));
  const [endTime, setEndTime] = useState(initialReport?.endTime || new Date(Date.now() + 3600000).toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' }));

  const [contractNumber, setContractNumber] = useState(initialReport?.contractNumber || '');
  const [routeNumber, setRouteNumber] = useState(initialReport?.routeNumber || '');

  // Initialize criteria: from initialReport if editing/viewing, otherwise from template
  const [criteria, setCriteria] = useState<AuditCriteria[]>(
    initialReport 
      ? initialReport.criteria 
      : template.defaultCriteria.map((c, idx) => ({
          id: `crit-${idx}`,
          label: c.label,
          status: null,
          notes: ''
        }))
  );

  const [summary, setSummary] = useState(initialReport?.summary || '');
  const [clientObservations, setClientObservations] = useState(initialReport?.clientObservations || '');

  // --- ORDER STATE ---
  const [orderItems, setOrderItems] = useState<OrderItem[]>(initialReport?.order?.items || []);
  const [orderDeliveryConditions, setOrderDeliveryConditions] = useState(initialReport?.order?.deliveryConditions || '');
  const [orderObservations, setOrderObservations] = useState(initialReport?.order?.observations || '');
  const [orderTotal, setOrderTotal] = useState(initialReport?.order?.totalValue || 0);

  // Recalculate total when items change
  useEffect(() => {
    const total = orderItems.reduce((acc, item) => acc + item.total, 0);
    setOrderTotal(total);
  }, [orderItems]);

  // Signature States
  const [auditorName, setAuditorName] = useState(initialReport?.auditorSignerName || auditor.name);
  const [auditorSignature, setAuditorSignature] = useState<string | null>(initialReport?.auditorSignature || null);

  const [clientName, setClientName] = useState(initialReport?.clientSignerName || client.contactPerson);
  const [clientSignature, setClientSignature] = useState<string | null>(initialReport?.clientSignature || null);

  const [gpsCoords, setGpsCoords] = useState<{lat: number, lng: number} | undefined>(initialReport?.gpsLocation);

  const isCommercialVisit = template.key === 'visit_comercial';
  const hasCriteria = criteria.length > 0;
  const isGeneralIntervention = template.key === 'intervention_general';

  // VAT Calculations
  const vatRate = 0.23;
  const vatAmount = orderTotal * vatRate;
  const grandTotal = orderTotal + vatAmount;

  const handleCriteriaStatusChange = (id: string, status: AuditCriteria['status']) => {
    if (readOnly) return;
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, status } : c));
  };

  const handleCriteriaNotesChange = (id: string, notes: string) => {
    setCriteria(prev => prev.map(c => c.id === id ? { ...c, notes } : c));
  };

  // --- Order Logic ---
  const addOrderItem = () => {
      const newItem: OrderItem = {
          id: `item-${Date.now()}`,
          productName: '',
          quantity: 1,
          unitPrice: 0,
          discount: 0,
          total: 0
      };
      setOrderItems([...orderItems, newItem]);
  };

  const updateOrderItem = (id: string, field: keyof OrderItem, value: any) => {
      const updatedItems = orderItems.map(item => {
          if (item.id === id) {
              // Ensure numeric fields are actually numbers
              let finalValue = value;
              if (['quantity', 'unitPrice', 'discount'].includes(field)) {
                  finalValue = value === '' ? 0 : parseFloat(value);
              }

              const updated = { ...item, [field]: finalValue };

              // Recalculate line total using valid numbers
              const qty = Number(updated.quantity);
              const price = Number(updated.unitPrice);
              const disc = Number(updated.discount);

              updated.total = (qty * price) * (1 - disc / 100);

              return updated;
          }
          return item;
      });
      setOrderItems(updatedItems);
  };

  const removeOrderItem = (id: string) => {
      setOrderItems(orderItems.filter(i => i.id !== id));
  };

  const handleFinish = async (action: 'save' | 'pdf' | 'email' | 'order_pdf') => {
    // Basic validation only if saving
    if (action === 'save') {
      // Validate signatures ONLY if NOT a commercial visit
      if (!isCommercialVisit) {
        if (!auditorSignature || !clientSignature) {
          alert("Ambas as assinaturas são obrigatórias para este tipo de relatório.");
          return;
        }
        if (!auditorName.trim() || !clientName.trim()) {
          alert("Os nomes dos signatários são obrigatórios.");
          return;
        }
      }

      if (!window.confirm("Deseja gravar o relatório?")) {
        return;
      }
    }

    // Capture GPS logic (skip if readOnly or just exporting PDF)
    let location = gpsCoords;
    if (action === 'save' && !readOnly && !location && "geolocation" in navigator) {
      try {
        const position = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject);
        });
        location = { lat: position.coords.latitude, lng: position.coords.longitude };
        setGpsCoords(location);
      } catch (e) {
        console.warn("Could not get GPS", e);
      }
    }

    // Construct data object
    const reportData: Report = {
      id: initialReport?.id || `r-${Date.now()}`,
      clientId: client.id,
      clientName: client.name,
      clientShopName: client.shopName,
      auditorId: auditor.id,
      auditorName: auditor.name, 
      date,
      startTime,
      endTime,
      contractNumber,
      routeNumber,
      typeKey: template.key,
      typeName: template.label,
      criteria,
      summary,
      clientObservations,
      auditorSignerName: auditorName,
      auditorSignature,
      clientSignerName: clientName,
      clientSignature,
      gpsLocation: location,
      status: 'Finalizado',
      // Attach order if it exists
      order: orderItems.length > 0 ? {
          items: orderItems,
          deliveryConditions: orderDeliveryConditions,
          observations: orderObservations,
          totalValue: orderTotal
      } : undefined
    };

    if (action === 'pdf' || action === 'email') {
      const doc = generatePDF(reportData, client, companySettings);

      if (action === 'pdf') {
        doc.save(`Relatorio_${client.name.replace(/\s+/g, '_')}_${date}.pdf`);
      } else {
        const subject = encodeURIComponent(`Relatório de Intervenção - ${client.name}`);
        const body = encodeURIComponent(`Segue em anexo o relatório da intervenção realizada dia ${date}.\n\nCumprimentos,\n${companySettings.name}`);
        window.open(`mailto:${client.email}?subject=${subject}&body=${body}`);
        doc.save(`Relatorio_${client.name}_${date}.pdf`); 
        alert("O cliente de email foi aberto.");
      }
    }

    if (action === 'order_pdf') {
        const doc = generateOrderPDF(reportData, client, companySettings);
        doc.save(`Encomenda_${client.name.replace(/\s+/g, '_')}_${date}.pdf`);
    }

    if (action === 'save') {
      onSave(reportData);
    }
  };

  // Title logic
  let title = 'Novo Relatório';
  if (initialReport) title = readOnly ? 'Visualizar Relatório' : 'Editar Relatório';

  return (
    <div className="flex flex-col h-full bg-gray-50 fixed inset-0 z-50 overflow-hidden">
      {/* Sticky Header */}
      <div className="bg-white border-b shadow-sm px-4 md:px-6 py-4 flex justify-between items-center shrink-0 z-20">
        <div className="overflow-hidden mr-4">
          <h2 className="text-lg md:text-xl font-bold text-gray-800 truncate">{title}</h2>
          <p className="text-xs md:text-sm font-semibold text-blue-600 truncate">{template.label}</p>
        </div>
        <div className="flex gap-2">
          <button type="button" onClick={onCancel} className="px-3 py-2 text-gray-700 bg-gray-100 rounded-lg font-medium hover:bg-gray-200 text-sm flex items-center gap-2">
            {readOnly ? <X size={16}/> : null}
            {readOnly ? 'Fechar' : 'Cancelar'}
          </button>

          <button onClick={() => handleFinish('email')} className="hidden md:flex px-3 py-2 bg-indigo-100 text-indigo-700 rounded-lg font-medium hover:bg-indigo-200 items-center gap-2 text-sm">
             <Mail size={16} /> Enviar
          </button>

          {/* Export Options */}
          <div className="hidden md:flex gap-1">
               <button onClick={() => handleFinish('pdf')} className="px-3 py-2 bg-indigo-100 text-indigo-700 rounded-l-lg font-medium hover:bg-indigo-200 items-center gap-2 text-sm flex border-r border-indigo-200">
                <Download size={16} /> PDF Relatório
              </button>
              {isCommercialVisit && orderItems.length > 0 && (
                <button onClick={() => handleFinish('order_pdf')} className="px-3 py-2 bg-emerald-100 text-emerald-700 rounded-r-lg font-medium hover:bg-emerald-200 items-center gap-2 text-sm flex" title="PDF apenas da Encomenda">
                    <ShoppingCart size={16} /> PDF Enc.
                </button>
              )}
          </div>

          {!readOnly && (
            <button onClick={() => handleFinish('save')} className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center gap-2 shadow-lg shadow-blue-200 text-sm">
              <Save size={16} /> <span className="hidden sm:inline">Finalizar</span>
            </button>
          )}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-6 w-full mx-auto">
        <div className="max-w-[1200px] mx-auto space-y-6 pb-20">

          {/* Info Section */}
          <div className="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100">
             <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Data</label>
                <input 
                  type="date" 
                  value={date} 
                  disabled={readOnly}
                  onChange={e => setDate(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Início</label>
                <input 
                  type="time" 
                  value={startTime}
                  disabled={readOnly}
                  onChange={e => setStartTime(e.target.value)} 
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Fim</label>
                <input 
                  type="time" 
                  value={endTime}
                  disabled={readOnly}
                  onChange={e => setEndTime(e.target.value)} 
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                 <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">GPS</label>
                 {gpsCoords ? (
                    <button 
                      type="button"
                      onClick={() => window.open(`https://www.google.com/maps/search/?api=1&query=${gpsCoords.lat},${gpsCoords.lng}`, '_blank')}
                      className="w-full p-2 bg-green-50 text-green-700 border border-green-200 rounded-lg flex items-center gap-2 truncate hover:bg-green-100 transition-colors"
                      title="Clique para ver no mapa"
                    >
                      <MapPin size={16} />
                      <span className="text-xs font-medium">Ver Mapa</span>
                      <ExternalLink size={12} className="opacity-50" />
                    </button>
                 ) : (
                   <div className="w-full p-2 bg-gray-50 text-gray-400 border border-gray-200 rounded-lg flex items-center gap-2 truncate">
                      <MapPin size={16} />
                      <span className="text-xs">Não capturado</span>
                   </div>
                 )}
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Nº Contrato</label>
                <input 
                  type="text" 
                  placeholder="Ex: 12345/24"
                  value={contractNumber} 
                  disabled={readOnly}
                  onChange={e => setContractNumber(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Nº Rota</label>
                <input 
                  type="text" 
                  placeholder="Ex: R-01"
                  value={routeNumber} 
                  disabled={readOnly}
                  onChange={e => setRouteNumber(e.target.value)}
                  className="w-full p-2 bg-white text-black border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-60 disabled:bg-gray-100" 
                />
              </div>
            </div>
          </div>

          {/* Criteria Evaluation */}
          {hasCriteria && (
            <div className="space-y-4">
              <h3 className="text-lg font-bold text-gray-800 px-2">Grelha de Avaliação</h3>
              <div className="grid grid-cols-1 gap-4">
                {criteria.map((item) => (
                  <div key={item.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                    <p className="font-semibold text-gray-900 mb-3 text-lg">{item.label}</p>

                    {/* Tablet Optimized Buttons: Full width Grid */}
                    <div className="grid grid-cols-3 gap-2 mb-3 h-14">
                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'pass')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'pass' 
                            ? 'bg-green-600 border-green-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'pass' ? 'hover:bg-green-50' : ''} ${readOnly && item.status !== 'pass' ? 'opacity-30' : ''}`}
                      >
                        <CheckCircle size={24} className={item.status === 'pass' ? 'mr-2' : ''} />
                        {item.status === 'pass' && <span className="font-bold">OK</span>}
                      </button>

                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'fail')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'fail' 
                            ? 'bg-red-600 border-red-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'fail' ? 'hover:bg-red-50' : ''} ${readOnly && item.status !== 'fail' ? 'opacity-30' : ''}`}
                      >
                        <AlertCircle size={24} className={item.status === 'fail' ? 'mr-2' : ''} />
                         {item.status === 'fail' && <span className="font-bold">NOK</span>}
                      </button>

                      <button
                        type="button"
                        disabled={readOnly}
                        onClick={() => handleCriteriaStatusChange(item.id, 'na')}
                        className={`flex items-center justify-center rounded-lg border transition-all active:scale-95 ${
                          item.status === 'na' 
                            ? 'bg-gray-600 border-gray-600 text-white shadow-md' 
                            : 'bg-white border-gray-200 text-gray-400'
                        } ${!readOnly && item.status !== 'na' ? 'hover:bg-gray-100' : ''} ${readOnly && item.status !== 'na' ? 'opacity-30' : ''}`}
                      >
                        <MinusCircle size={24} className={item.status === 'na' ? 'mr-2' : ''} />
                         {item.status === 'na' && <span className="font-bold">N/A</span>}
                      </button>
                    </div>

                    {/* Notes */}
                    <textarea
                      placeholder="Observações..."
                      value={item.notes}
                      disabled={readOnly}
                      onChange={e => handleCriteriaNotesChange(item.id, e.target.value)}
                      rows={1}
                      className="w-full p-3 bg-white text-black border-b border-gray-300 focus:bg-white focus:border-blue-500 outline-none transition-colors text-base rounded-lg disabled:opacity-70"
                    />
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* COMMERCIAL VISIT - ORDER SECTION */}
          {isCommercialVisit && (
              <div className="space-y-4">
                  <div className="flex justify-between items-center px-2">
                    <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                        <ShoppingCart size={20} className="text-emerald-600" /> Nova Encomenda
                    </h3>
                    {!readOnly && (
                        <button onClick={addOrderItem} className="bg-emerald-600 text-white px-3 py-1 rounded-lg text-sm flex items-center gap-1 hover:bg-emerald-700">
                            <Plus size={16} /> Adicionar Produto
                        </button>
                    )}
                  </div>

                  <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                      <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 border-b border-gray-200">
                                <tr>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-1/3">Produto</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-20">Qtd</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-24">Preço (€)</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase w-20">Desc.%</th>
                                    <th className="px-4 py-3 text-xs font-semibold text-gray-500 uppercase text-right">Total</th>
                                    {!readOnly && <th className="px-4 py-3 w-10"></th>}
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {orderItems.map((item) => (
                                    <tr key={item.id}>
                                        <td className="p-2">
                                            <input 
                                                className="w-full p-2 border rounded bg-white text-gray-900"
                                                placeholder="Descrição do produto"
                                                value={item.productName}
                                                onChange={(e) => updateOrderItem(item.id, 'productName', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                            <input 
                                                type="number"
                                                min="1"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-center"
                                                value={item.quantity}
                                                onChange={(e) => updateOrderItem(item.id, 'quantity', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                            <input 
                                                type="number"
                                                min="0"
                                                step="0.01"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-right"
                                                value={item.unitPrice}
                                                onChange={(e) => updateOrderItem(item.id, 'unitPrice', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2">
                                             <input 
                                                type="number"
                                                min="0"
                                                max="100"
                                                className="w-full p-2 border rounded bg-white text-gray-900 text-center"
                                                value={item.discount}
                                                onChange={(e) => updateOrderItem(item.id, 'discount', e.target.value)}
                                                disabled={readOnly}
                                            />
                                        </td>
                                        <td className="p-2 text-right font-bold text-gray-800">
                                            {item.total.toFixed(2)}€
                                        </td>
                                        {!readOnly && (
                                            <td className="p-2 text-center">
                                                <button onClick={() => removeOrderItem(item.id)} className="text-red-500 hover:text-red-700">
                                                    <Trash2 size={18} />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                ))}
                                {orderItems.length === 0 && (
                                    <tr>
                                        <td colSpan={6} className="p-4 text-center text-gray-400 text-sm">
                                            Nenhum produto adicionado à encomenda.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                            <tfoot className="bg-gray-50 font-bold">
                                <tr>
                                    <td colSpan={4} className="px-4 py-2 text-right text-gray-600 text-sm">Subtotal:</td>
                                    <td className="px-4 py-2 text-right text-gray-700">{orderTotal.toFixed(2)}€</td>
                                    {!readOnly && <td></td>}
                                </tr>
                                <tr>
                                    <td colSpan={4} className="px-4 py-2 text-right text-gray-600 text-sm">IVA (23%):</td>
                                    <td className="px-4 py-2 text-right text-gray-700">{vatAmount.toFixed(2)}€</td>
                                    {!readOnly && <td></td>}
                                </tr>
                                <tr className="bg-emerald-50 border-t border-emerald-100">
                                    <td colSpan={4} className="px-4 py-3 text-right text-emerald-900 font-bold">Total Final (c/ IVA):</td>
                                    <td className="px-4 py-3 text-right text-emerald-700 text-lg font-bold">{grandTotal.toFixed(2)}€</td>
                                    {!readOnly && <td></td>}
                                </tr>
                            </tfoot>
                        </table>
                      </div>

                      <div className="p-4 bg-emerald-50 border-t border-emerald-100 grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div>
                              <label className="block text-xs font-bold text-emerald-800 uppercase mb-1">Condições de Entrega</label>
                              <input 
                                value={orderDeliveryConditions}
                                onChange={(e) => setOrderDeliveryConditions(e.target.value)}
                                disabled={readOnly}
                                className="w-full p-2 border border-emerald-200 rounded bg-white text-gray-900"
                                placeholder="Ex: Entrega em 48h, Portes incluídos..."
                              />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-emerald-800 uppercase mb-1">Observações da Encomenda</label>
                              <input 
                                value={orderObservations}
                                onChange={(e) => setOrderObservations(e.target.value)}
                                disabled={readOnly}
                                className="w-full p-2 border border-emerald-200 rounded bg-white text-gray-900"
                                placeholder="Notas internas ou para faturação..."
                              />
                          </div>
                      </div>
                  </div>
              </div>
          )}

          {/* Main Report / Summary Section */}
          <div className="bg-indigo-50 p-6 rounded-xl border border-indigo-100">
            <h3 className="text-lg font-semibold text-indigo-900 mb-3 flex items-center gap-2">
              <FileText size={20} /> {isGeneralIntervention ? 'Relatório da Intervenção' : 'Resumo e Conclusões'}
            </h3>
            <textarea
              value={summary}
              disabled={readOnly}
              onChange={e => setSummary(e.target.value)}
              placeholder={isGeneralIntervention ? "Descreva detalhadamente a intervenção realizada..." : "Escreva um resumo e conclusões..."}
              className={`w-full p-4 bg-white text-black border border-indigo-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm ${isGeneralIntervention ? 'h-64' : 'h-32'} disabled:bg-gray-100 disabled:text-gray-700`}
            />
          </div>

          {/* Client Observations */}
          <div className="bg-amber-50 p-6 rounded-xl border border-amber-100">
            <h3 className="text-lg font-semibold text-amber-900 mb-3">Observações do Cliente</h3>
            <textarea
              value={clientObservations}
              disabled={readOnly}
              onChange={e => setClientObservations(e.target.value)}
              placeholder="Registe aqui quaisquer observações ou comentários do cliente..."
              className="w-full p-4 bg-white text-black border border-amber-200 rounded-lg h-24 outline-none focus:ring-2 focus:ring-amber-500 shadow-sm disabled:bg-gray-100 disabled:text-gray-700"
            />
          </div>

          {/* Signatures - HIDE FOR COMMERCIAL VISITS */}
          {!isCommercialVisit && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

              <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Técnico (Auditor)</label>
                <input 
                  type="text" 
                  value={auditorName} 
                  disabled={readOnly}
                  onChange={e => setAuditorName(e.target.value)}
                  className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded outline-none disabled:bg-gray-100"
                />
                <SignaturePad 
                  label="Assinatura"
                  onEnd={setAuditorSignature}
                  initialData={auditorSignature}
                  disabled={readOnly}
                />
              </div>

              <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                 <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">Cliente</label>
                 <input 
                  type="text" 
                  value={clientName} 
                  disabled={readOnly}
                  onChange={e => setClientName(e.target.value)}
                  className="w-full p-2 mb-4 bg-white text-black border border-gray-300 rounded outline-none disabled:bg-gray-100"
                />
                <SignaturePad 
                  label="Assinatura"
                  onEnd={setClientSignature}
                  initialData={clientSignature}
                  disabled={readOnly}
                />
              </div>

            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default ReportForm;

import { Report, CompanySettings, Client } from '../types';

// Declare globals for the script tags loaded in index.html
declare global {
  interface Window {
    jspdf: any;
    jsPDF: any; // Shim global
  }
}

// Constants for styling
const COLORS: { [key: string]: [number, number, number] } = {
  PRIMARY: [30, 58, 138], // Blue-900
  SECONDARY: [100, 116, 139], // Slate-500
  ACCENT: [241, 245, 249], // Slate-100 (Backgrounds)
  TEXT: [15, 23, 42], // Slate-900
  OK: [22, 163, 74], // Green-600
  NOK: [220, 38, 38], // Red-600
  NA: [148, 163, 184] // Slate-400
};

export const generatePDF = (report: Report, client: Client, company: CompanySettings) => {
  try {
    // Access jsPDF from the global window object (loaded via script tag)
    if (!window.jspdf) {
      alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
      throw new Error("jsPDF not loaded");
    }

    const jsPDF = window.jspdf.jsPDF;
    const doc = new jsPDF();

    // Verify AutoTable Plugin
    if (typeof (doc as any).autoTable !== 'function') {
       alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
       throw new Error("AutoTable plugin missing");
    }

    const pageWidth = doc.internal.pageSize.width;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 14;
    const contentWidth = pageWidth - (margin * 2);

    // Helper: Draw Section Title
    const drawSectionTitle = (title: string, y: number) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(title.toUpperCase(), margin, y);
      doc.setDrawColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.setLineWidth(0.5);
      doc.line(margin, y + 1.5, margin + 40, y + 1.5); // Underline part
      return y + 6;
    };

    // Helper: Draw Field
    const drawField = (label: string, value: string, x: number, y: number, maxWidth: number = 80) => {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(label, x, y);

      doc.setFont('helvetica', 'normal');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      // Handle long text wrapping
      const splitText = doc.splitTextToSize(value, maxWidth);
      doc.text(splitText, x, y + 4);

      return (splitText.length * 3.5) + 3; // Return height used
    };

    // --- 1. HEADER ---
    let y = 15;

    // Logo (Left)
    if (company.logoUrl) {
      try {
        doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
      } catch (e) {
        console.warn("Logo error", e);
      }
    }

    // Company Info (Right Aligned)
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text(company.name, pageWidth - margin, y, { align: 'right' });
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text(company.address, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(`${company.postalCode || ''} ${company.locality || ''}`, pageWidth - margin, y, { align: 'right' }); 
    y += 4;
    doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });
    y += 4;
    doc.text(company.email, pageWidth - margin, y, { align: 'right' });

    // Document Title Bar
    y = 42;
    doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.rect(margin, y, contentWidth, 10, 'F');

    doc.setTextColor(255, 255, 255);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text("RELATÓRIO DE INTERVENÇÃO TÉCNICA", margin + 4, y + 6.5);

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9);
    doc.text(`Nº ${report.id.replace('r-', '')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

    // --- 2. INFO GRID (Client & Intervention) ---
    y += 15;
    const boxHeight = 42;
    const colWidth = (contentWidth / 2) - 4;

    // Draw Background Boxes
    doc.setFillColor(COLORS.ACCENT[0], COLORS.ACCENT[1], COLORS.ACCENT[2]);
    doc.roundedRect(margin, y, colWidth, boxHeight, 2, 2, 'F'); // Client Box
    doc.roundedRect(margin + colWidth + 8, y, colWidth, boxHeight, 2, 2, 'F'); // Intervention Box

    // Client Data
    let cy = y + 6;
    const cx = margin + 4;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("CLIENTE", cx, cy);
    cy += 6;

    cy += drawField("Nome / Empresa", client.name, cx, cy, colWidth - 8);
    cy += drawField("Localização", `${client.address}, ${client.locality}`, cx, cy, colWidth - 8);

    // Quick contact line
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Contacto:", cx, cy + 4);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${client.contactPerson} (${client.phone})`, cx + 18, cy + 4);

    // Intervention Data
    let iy = y + 6;
    const ix = margin + colWidth + 12;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(9);
    doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
    doc.text("DETALHES DO SERVIÇO", ix, iy);
    iy += 6;

    // Compact line for times
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
    doc.text("Horário:", ix, iy);
    doc.text("Técnico:", ix + (colWidth/2), iy);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
    doc.text(`${report.startTime} - ${report.endTime}`, ix, iy + 4);
    doc.text(report.auditorName.split(' ')[0], ix + (colWidth/2), iy + 4);
    iy += 9;

    iy += drawField("Tipo de Serviço", report.typeName, ix, iy, colWidth - 8);
    if (report.contractNumber || report.routeNumber) {
      drawField("Contrato / Rota", `${report.contractNumber || '-'} / ${report.routeNumber || '-'}`, ix, iy, colWidth - 8);
    }

    y += boxHeight + 8;

    // --- 3. CRITERIA TABLE ---
    if (report.criteria && report.criteria.length > 0) {
      const tableData = report.criteria.map(c => [
        c.label,
        c.status === 'pass' ? 'OK' : c.status === 'fail' ? 'NOK' : 'N/A',
        c.notes || ''
      ]);

      // Use method attached to prototype by script tag
      (doc as any).autoTable({
        startY: y,
        head: [['CRITÉRIO AVALIADO', 'ESTADO', 'OBSERVAÇÕES TÉCNICAS']],
        body: tableData,
        theme: 'plain', // Clean look
        styles: {
          fontSize: 7,
          cellPadding: 2,
          font: 'helvetica',
          textColor: COLORS.TEXT,
          lineColor: [226, 232, 240], // Slate-200
          lineWidth: 0.1,
        },
        headStyles: {
          fillColor: COLORS.ACCENT,
          textColor: COLORS.PRIMARY,
          fontStyle: 'bold',
          fontSize: 7,
        },
        columnStyles: {
          0: { cellWidth: 80, fontStyle: 'bold' },
          1: { cellWidth: 20, halign: 'center', fontStyle: 'bold' },
          2: { cellWidth: 'auto' }
        },
        didParseCell: function(data: any) {
          // Color coding for Status
          if (data.section === 'body' && data.column.index === 1) {
            const text = data.cell.text[0];
            if (text === 'OK') data.cell.styles.textColor = COLORS.OK;
            if (text === 'NOK') data.cell.styles.textColor = COLORS.NOK;
            if (text === 'N/A') data.cell.styles.textColor = COLORS.NA;
          }
          // Zebra striping manually for cleaner look
          if (data.section === 'body' && data.row.index % 2 === 1) {
             data.cell.styles.fillColor = [248, 250, 252]; // Slate-50
          }
        },
        margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 8;
    }

    // --- 3.5 ORDER TABLE (If exists) ---
    if (report.order && report.order.items.length > 0) {

      // Check if we need new page before order
      if (pageHeight - y < 60) {
          doc.addPage();
          y = 20;
      }

      drawSectionTitle("Nota de Encomenda", y);
      y += 5;

      const orderData = report.order.items.map(item => [
          item.productName,
          String(item.quantity),
          `${Number(item.unitPrice).toFixed(2)}€`,
          `${item.discount}%`,
          `${Number(item.total).toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'plain',
          styles: {
              fontSize: 7,
              cellPadding: 2,
              font: 'helvetica',
              textColor: COLORS.TEXT,
              lineColor: [226, 232, 240],
              lineWidth: 0.1,
          },
          headStyles: {
              fillColor: COLORS.PRIMARY,
              textColor: [255, 255, 255],
              fontStyle: 'bold',
              fontSize: 7,
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 20, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 4;

      // VAT Calculations
      const subtotal = report.order.totalValue;
      const vatRate = 0.23;
      const vatAmount = subtotal * vatRate;
      const grandTotal = subtotal + vatAmount;

      // Total Value Block
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

      doc.text(`Subtotal:`, pageWidth - margin - 35, y, { align: 'right' });
      doc.text(`${subtotal.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 5;

      doc.text(`IVA (23%):`, pageWidth - margin - 35, y, { align: 'right' });
      doc.text(`${vatAmount.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 5;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(`Total Final:`, pageWidth - margin - 35, y, { align: 'right' });
      doc.text(`${grandTotal.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 8;

      // Delivery Conditions & Obs
      if (report.order.deliveryConditions || report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(8);
          doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);

          if (report.order.deliveryConditions) {
              doc.text("Condições de Entrega:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.deliveryConditions, margin + 35, y);
              y += 5;
          }

          if (report.order.observations) {
              doc.setFont('helvetica', 'bold');
              doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
              doc.text("Obs. Encomenda:", margin, y);
              doc.setFont('helvetica', 'normal');
              doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
              doc.text(report.order.observations, margin + 35, y);
              y += 5;
          }
      }
      y += 4;
    }

    // --- 4. OBSERVATIONS & SUMMARY ---

    // Check space for observations. If minimal space left, add page.
    if (pageHeight - y < 90) {
      doc.addPage();
      y = 20;
    }

    // Summary Box
    drawSectionTitle("Resumo e Conclusões", y);
    y += 5;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);

    const summaryText = report.summary || "Sem observações adicionais a registar.";
    const splitSummary = doc.splitTextToSize(summaryText, contentWidth);
    doc.text(splitSummary, margin, y);
    y += (splitSummary.length * 4) + 8;

    // Client Obs (if exists)
    if (report.clientObservations) {
      drawSectionTitle("Observações do Cliente", y);
      y += 5;
      const clientObsText = report.clientObservations;
      const splitClientObs = doc.splitTextToSize(clientObsText, contentWidth);
      doc.setFont('helvetica', 'italic');
      doc.text(splitClientObs, margin, y);
      doc.setFont('helvetica', 'normal');
      y += (splitClientObs.length * 4) + 8;
    }

    // --- 5. SIGNATURES (Anchored Bottom) ---

    // Only draw signatures if NOT a commercial visit
    if (report.typeKey !== 'visit_comercial') {

      // Calculate footer area height required (approx 45 units)
      const footerHeight = 45;
      let sigY = pageHeight - footerHeight - 10; // 10 padding from bottom edge

      // If current content overlaps signature area, push signatures to next page
      if (y > sigY) {
        doc.addPage();
        sigY = pageHeight - footerHeight - 10;
      }

      // Draw light separator line
      doc.setDrawColor(226, 232, 240);
      doc.line(margin, sigY, pageWidth - margin, sigY);
      sigY += 5;

      const sigBoxWidth = (contentWidth / 2) - 10;
      const sigBoxHeight = 35;

      // Auditor Signature Area
      const aX = margin;
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(report.order ? "COMERCIAL" : "TÉCNICO RESPONSÁVEL", aX, sigY + 3);

      if (report.auditorSignature) {
        try {
          doc.addImage(report.auditorSignature, 'PNG', aX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Auditor signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.setLineWidth(0.1);
      doc.line(aX, sigY + 25, aX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.auditorName, aX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Assinado digitalmente", aX, sigY + 32);

      // Client Signature Area
      const cX = pageWidth - margin - sigBoxWidth;
      doc.setFontSize(7);
      doc.text("PELO CLIENTE", cX, sigY + 3);

      if (report.clientSignature) {
        try {
          doc.addImage(report.clientSignature, 'PNG', cX, sigY + 5, 40, 18);
        } catch(e) { console.warn("Client signature error", e); }
      }
      doc.setDrawColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.line(cX, sigY + 25, cX + sigBoxWidth, sigY + 25); // Signature Line

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(7);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(report.clientSignerName, cX, sigY + 29);
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Validado no local", cX, sigY + 32);
    } else {
      // If commercial visit, maybe just add a small footer note or nothing
      let noteY = pageHeight - 15;
      if (y > noteY) {
          doc.addPage();
          noteY = pageHeight - 15;
      }
      doc.setFontSize(7);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text("Relatório de visita comercial (não carece de assinatura).", margin, noteY);
    }

    // --- 6. FOOTER (Page Numbers) ---
    const pageCount = (doc as any).internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
      doc.setPage(i);
      doc.setFontSize(6);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      const footerText = `AuditPro 360 | Processado informaticamente | Pág. ${i}/${pageCount}`;
      doc.text(footerText, pageWidth / 2, pageHeight - 5, { align: 'center' });
    }

    return doc;

  } catch (err) {
    console.error("Critical PDF Generation Error", err);
    alert(`Erro ao gerar PDF: ${(err as Error).message}`);
    throw err;
  }
};

// Function to generate ONLY the Order PDF
export const generateOrderPDF = (report: Report, client: Client, company: CompanySettings) => {
    try {
      // Access jsPDF from the global window object (loaded via script tag)
      if (!window.jspdf) {
          alert("Erro: Biblioteca PDF não carregada. Verifique a sua ligação à internet.");
          throw new Error("jsPDF not loaded");
      }

      if (!report.order) return generatePDF(report, client, company); // Fallback

      const jsPDF = window.jspdf.jsPDF;
      const doc = new jsPDF();

      // Verify AutoTable Plugin
      if (typeof (doc as any).autoTable !== 'function') {
        alert("Erro: Plugin de tabelas (AutoTable) não carregou corretamente. Tente atualizar a página.");
        throw new Error("AutoTable plugin missing");
      }

      const pageWidth = doc.internal.pageSize.width;
      const pageHeight = doc.internal.pageSize.height;
      const margin = 14;
      const contentWidth = pageWidth - (margin * 2);

      let y = 15;

      // --- Header (Similar to main report but specific title) ---
      if (company.logoUrl) {
          try {
            doc.addImage(company.logoUrl, 'PNG', margin, 10, 25, 25);
          } catch (e) {
            console.warn("Logo error", e);
          }
      }

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text(company.name, pageWidth - margin, y, { align: 'right' });
      y += 5;

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.setTextColor(COLORS.SECONDARY[0], COLORS.SECONDARY[1], COLORS.SECONDARY[2]);
      doc.text(company.address, pageWidth - margin, y, { align: 'right' });
      y += 4;
      doc.text(`NIF: ${company.nif} | ${company.phone}`, pageWidth - margin, y, { align: 'right' });

      // Document Title Bar
      y = 42;
      doc.setFillColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.rect(margin, y, contentWidth, 10, 'F');

      doc.setTextColor(255, 255, 255);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.text("NOTA DE ENCOMENDA", margin + 4, y + 6.5);

      doc.setFont('helvetica', 'normal');
      doc.setFontSize(9);
      doc.text(`Ref: ${report.id.replace('r-', 'enc-')} | Data: ${report.date}`, pageWidth - margin - 4, y + 6.5, { align: 'right' });

      // Client Info
      y += 15;

      // Commercial Name Header
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(`Comercial: ${report.auditorName}`, margin, y);

      y += 10;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(10);
      doc.setTextColor(COLORS.PRIMARY[0], COLORS.PRIMARY[1], COLORS.PRIMARY[2]);
      doc.text("DADOS DO CLIENTE", margin, y);
      y += 5;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(COLORS.TEXT[0], COLORS.TEXT[1], COLORS.TEXT[2]);
      doc.text(client.name, margin, y);
      y += 4;
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(8);
      doc.text(`${client.address}, ${client.postalCode} ${client.locality}`, margin, y);
      y += 4;
      doc.text(`NIF: ${client.nif || 'N/A'}`, margin, y);
      y += 4;
      doc.text(`Contacto: ${client.contactPerson} (${client.phone})`, margin, y);

      y += 10;

      // Order Table
      const orderData = report.order.items.map(item => [
          item.productName,
          String(item.quantity),
          `${Number(item.unitPrice).toFixed(2)}€`,
          `${item.discount}%`,
          `${Number(item.total).toFixed(2)}€`
      ]);

      (doc as any).autoTable({
          startY: y,
          head: [['Produto / Serviço', 'Qtd', 'Preço Unit.', 'Desc.', 'Total']],
          body: orderData,
          theme: 'striped',
          styles: { fontSize: 8 },
          headStyles: { 
              fillColor: COLORS.PRIMARY, 
              textColor: [255, 255, 255] 
          },
          columnStyles: {
              0: { cellWidth: 'auto' },
              1: { cellWidth: 15, halign: 'center' },
              2: { cellWidth: 25, halign: 'right' },
              3: { cellWidth: 15, halign: 'center' },
              4: { cellWidth: 25, halign: 'right', fontStyle: 'bold' }
          },
          margin: { left: margin, right: margin }
      });

      y = (doc as any).lastAutoTable.finalY + 5;

      // VAT Calculations
      const subtotal = report.order.totalValue;
      const vatRate = 0.23;
      const vatAmount = subtotal * vatRate;
      const grandTotal = subtotal + vatAmount;

      // Total and Conditions Block
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(10);

      doc.text(`Subtotal:`, pageWidth - margin - 40, y, { align: 'right' });
      doc.text(`${subtotal.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 6;

      doc.text(`IVA (23%):`, pageWidth - margin - 40, y, { align: 'right' });
      doc.text(`${vatAmount.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 6;

      doc.setFont('helvetica', 'bold');
      doc.setFontSize(12);
      doc.text(`Total Final:`, pageWidth - margin - 40, y, { align: 'right' });
      doc.text(`${grandTotal.toFixed(2)}€`, pageWidth - margin, y, { align: 'right' });
      y += 15;

      if (report.order.deliveryConditions) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Condições de Entrega:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.deliveryConditions, margin, y);
          y += 8;
      }

      if (report.order.observations) {
          doc.setFont('helvetica', 'bold');
          doc.setFontSize(9);
          doc.text("Observações:", margin, y);
          y += 4;
          doc.setFont('helvetica', 'normal');
          doc.text(report.order.observations, margin, y);
          y += 8;
      }

      // Signatures
      const sigY = pageHeight - 40;
      doc.setDrawColor(200, 200, 200);
      doc.line(margin, sigY, margin + 60, sigY);
      doc.line(pageWidth - margin - 60, sigY, pageWidth - margin, sigY);

      doc.setFontSize(8);
      // Explicitly showing Commercial Name under signature line
      doc.text("O Comercial", margin, sigY + 5);
      doc.setFont('helvetica', 'bold');
      doc.text(report.auditorName, margin, sigY + 10);

      doc.setFont('helvetica', 'normal');
      doc.text("O Cliente", pageWidth - margin - 60, sigY + 5);

      return doc;
    } catch (err) {
      console.error("Critical Order PDF Generation Error", err);
      alert(`Erro ao gerar PDF de Encomenda: ${(err as Error).message}`);
      throw err;
    }
};

import React, { useState, useEffect } from 'react';
import { 
  Users, 
  FileText, 
  Settings, 
  Plus, 
  ChevronRight, 
  Search,
  LayoutDashboard,
  Calendar,
  Briefcase,
  Edit2,
  Trash2,
  X,
  CheckSquare,
  Square,
  LogOut,
  Building,
  UserPlus,
  History,
  Mail,
  Download,
  Phone,
  MapPin,
  AtSign,
  Upload,
  Camera,
  Eye,
  AlertTriangle,
  ShoppingCart
} from 'lucide-react';
import { REPORT_TEMPLATES, DEFAULT_COMPANY_SETTINGS, MOCK_USERS, MOCK_CLIENTS, MOCK_REPORTS } from './constants';
import { User, Client, Report, UserRole, ReportTypeKey, CompanySettings } from './types';
import ReportForm from './components/ReportForm';
import LoginScreen from './components/LoginScreen';
import { generatePDF, generateOrderPDF } from './services/pdfService';
import { api } from './services/api';

enum Screen {
  DASHBOARD = 'Dashboard',
  CLIENTS = 'Clientes',
  REPORTS = 'Relatórios',
  SETTINGS = 'Configurações'
}

const App: React.FC = () => {
  // --- Global State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.DASHBOARD);

  // Data State - Initialize empty, load from API
  const [users, setUsers] = useState<User[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [reports, setReports] = useState<Report[]>([]);
  const [companySettings, setCompanySettings] = useState<CompanySettings>(DEFAULT_COMPANY_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  // Client Management State
  const [isClientModalOpen, setIsClientModalOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');

  // Client History State
  const [viewingHistoryClient, setViewingHistoryClient] = useState<Client | null>(null);

  // User Management State (Settings)
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  // Report Workflow State
  const [selectedClientForReport, setSelectedClientForReport] = useState<Client | null>(null);
  const [isReportTypeModalOpen, setIsReportTypeModalOpen] = useState(false);
  const [selectedTemplateKey, setSelectedTemplateKey] = useState<ReportTypeKey | null>(null);

  // Report Edit/View State
  const [editingReport, setEditingReport] = useState<Report | null>(null);
  const [viewingReport, setViewingReport] = useState<Report | null>(null);

  // --- API LOADING ---
  const loadData = async () => {
      setIsLoading(true);
      try {
          // Fetch all data in parallel
          const [fetchedUsers, fetchedClients, fetchedReports, fetchedSettings] = await Promise.all([
              api.getUsers(),
              api.getClients(),
              api.getReports(),
              api.getSettings()
          ]);

          // Hydrate Reports with Client/Auditor names (since SQL returns IDs)
          const hydratedReports = fetchedReports.map(r => {
              const client = fetchedClients.find(c => c.id === r.clientId);
              const auditor = fetchedUsers.find(u => u.id === r.auditorId);
              const template = Object.values(REPORT_TEMPLATES).find(t => t.key === r.typeKey);

              return {
                  ...r,
                  clientName: client ? client.name : 'Cliente Desconhecido',
                  clientShopName: client?.shopName,
                  auditorName: auditor ? auditor.name : 'Auditor Desconhecido',
                  typeName: template ? template.label : r.typeKey
              };
          });

          // Fallback if API returns empty/error (e.g. first run) use Constants, otherwise use API data
          // NOTE: For Production, remove the OR || fallback to force DB usage
          setUsers(fetchedUsers.length > 0 ? fetchedUsers : MOCK_USERS); 
          setClients(fetchedClients.length > 0 ? fetchedClients : MOCK_CLIENTS);
          // If reports are empty but users/clients loaded, it might just be empty DB.
          // Only fallback if EVERYTHING failed (users empty)
          setReports(fetchedUsers.length > 0 ? hydratedReports : MOCK_REPORTS);

          if (fetchedSettings) setCompanySettings(fetchedSettings);

      } catch (error) {
          console.error("Error loading data", error);
          // Fallback to mocks so app doesn't crash on dev without PHP
          setUsers(MOCK_USERS);
          setClients(MOCK_CLIENTS);
          setReports(MOCK_REPORTS);
      } finally {
          setIsLoading(false);
      }
  };

  useEffect(() => {
      loadData();
  }, []);


  // --- Derived State & Access Control ---

  const isAdmin = currentUser?.role === UserRole.ADMIN;

  // Filter Clients based on Role
  const availableClients = clients.filter(c => {
    if (!currentUser) return false;
    if (currentUser.role === UserRole.ADMIN) return true;
    if (currentUser.role === UserRole.COMERCIAL) {
        return c.accountManagerId === currentUser.id;
    }
    return true; // Auditors/Technicians usually see all or route based, keeping open for now
  });

  const filteredClients = availableClients.filter(c => 
    c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
    (c.nif && c.nif.includes(clientSearch))
  );

  // Filter Reports based on Role (Only see reports for clients you have access to)
  const availableReports = reports.filter(r => {
      const client = clients.find(c => c.id === r.clientId);
      if (!client) return false; // Or show if deleted?
      if (!currentUser) return false;

      if (currentUser.role === UserRole.ADMIN) return true;
      if (currentUser.role === UserRole.COMERCIAL) {
          return client.accountManagerId === currentUser.id;
      }
      return true; 
  });

  // Dashboard calculations
  const currentMonthReports = availableReports.filter(r => {
    const rDate = new Date(r.date);
    const now = new Date();
    return rDate.getMonth() === now.getMonth() && rDate.getFullYear() === now.getFullYear();
  });

  const recentReports = availableReports.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 5);

  // Order Calculations
  const currentMonthOrders = currentMonthReports.filter(r => r.order);
  const currentMonthOrderValue = currentMonthOrders.reduce((acc, r) => acc + (r.order?.totalValue || 0), 0);

  // Alert Calculations (Clients not visited) - Only calculated for display logic, but visibility controlled below
  const overdueClients = availableClients.filter(c => {
      if (!c.visitFrequency || !c.lastVisit || c.lastVisit === '-') return false;
      const last = new Date(c.lastVisit);
      const now = new Date();
      const diffTime = Math.abs(now.getTime() - last.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
      return diffDays > c.visitFrequency;
  });

  // --- Actions: Auth ---
  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setCurrentScreen(Screen.DASHBOARD);
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  // --- Actions: Clients ---

  const handleSaveClient = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    const clientData: Client = {
      id: editingClient ? editingClient.id : `c-${Date.now()}`,
      name: formData.get('name') as string,
      shopName: formData.get('shopName') as string,
      nif: formData.get('nif') as string,
      contactPerson: formData.get('contactPerson') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,

      address: formData.get('address') as string,
      postalCode: formData.get('postalCode') as string,
      locality: formData.get('locality') as string,
      county: formData.get('county') as string,

      visitFrequency: Number(formData.get('visitFrequency')) || undefined,

      status: 'Ativo',
      lastVisit: editingClient?.lastVisit || '-',

      // If creating as commercial, auto-assign. If admin, could add selector (skipping for brevity)
      accountManagerId: editingClient?.accountManagerId || (currentUser?.role === UserRole.COMERCIAL ? currentUser.id : undefined)
    };

    // Update Local State Optimistically
    if (editingClient) {
      setClients(clients.map(c => c.id === clientData.id ? clientData : c));
    } else {
      setClients([...clients, clientData]);
    }

    // Save to API
    await api.saveClient(clientData);

    setIsClientModalOpen(false);
    setEditingClient(null);
  };

  const handleDeleteClient = async (id: string) => {
    if (currentUser?.role !== UserRole.ADMIN) {
      alert("Apenas administradores podem apagar clientes.");
      return;
    }
    if (confirm('Tem a certeza que deseja remover este cliente?')) {
      // Optimistic Update
      setClients(clients.filter(c => c.id !== id));
      // API Call
      await api.deleteClient(id);
    }
  };

  const openEditClient = (client: Client) => {
    setEditingClient(client);
    setIsClientModalOpen(true);
  };

  const openAddClient = () => {
    setEditingClient(null);
    setIsClientModalOpen(true);
  };

  const openClientHistory = (client: Client) => {
    setViewingHistoryClient(client);
  };

  // --- Actions: Users ---

  const handleSaveUser = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);

    // Handle File Upload
    const fileInput = (e.currentTarget.elements.namedItem('avatarFile') as HTMLInputElement);
    let avatarUrl = editingUser?.avatar || `https://ui-avatars.com/api/?name=${formData.get('name')}&background=random`;

    if (fileInput.files && fileInput.files[0]) {
       const file = fileInput.files[0];
       avatarUrl = await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
       });
    }

    // Get Allowed Templates (Permissions)
    const allowedTemplates = formData.getAll('allowedTemplates') as ReportTypeKey[];

    const userData: User = {
      id: editingUser ? editingUser.id : `u-${Date.now()}`,
      name: formData.get('name') as string,
      role: formData.get('role') as UserRole,
      pin: formData.get('pin') as string,
      avatar: avatarUrl,
      allowedTemplates: allowedTemplates.length > 0 ? allowedTemplates : [] 
    };

    if (editingUser) {
      setUsers(users.map(u => u.id === userData.id ? userData : u));
    } else {
      setUsers([...users, userData]);
    }

    await api.saveUser(userData);

    setIsUserModalOpen(false);
    setEditingUser(null);
  };

  const handleDeleteUser = async (id: string) => {
    if (confirm('Tem a certeza?')) {
        setUsers(users.filter(u => u.id !== id));
        await api.deleteUser(id);
    }
  };

  // --- Actions: Reports ---

  const initReportCreation = (client: Client) => {
    setSelectedClientForReport(client);
    setEditingReport(null); // Ensure we are not editing
    setViewingReport(null);
    setIsReportTypeModalOpen(true);
  };

  const selectReportType = (key: ReportTypeKey) => {
    setSelectedTemplateKey(key);
    setIsReportTypeModalOpen(false);
  };

  const handleEditReport = (report: Report) => {
    // Only Admin or the Author can edit (simplified to Admin for now based on prompt, but logical extension)
    if (currentUser?.role !== UserRole.ADMIN) return;
    const client = clients.find(c => c.id === report.clientId);
    if (!client) return;

    setSelectedClientForReport(client);
    setSelectedTemplateKey(report.typeKey);
    setEditingReport(report);
    setViewingReport(null);
  };

  const handleViewReport = (report: Report) => {
    const client = clients.find(c => c.id === report.clientId);
    if (!client) return;

    setSelectedClientForReport(client);
    setSelectedTemplateKey(report.typeKey);
    setViewingReport(report);
    setEditingReport(null);
  };

  const handleSaveReport = async (report: Report) => {
    // Check if updating or creating
    const exists = reports.some(r => r.id === report.id);

    if (exists) {
      setReports(reports.map(r => r.id === report.id ? report : r));
    } else {
      setReports([report, ...reports]);
      // Update client last visit
      const updatedClient = clients.find(c => c.id === report.clientId);
      if(updatedClient) {
          const newClientData = { ...updatedClient, lastVisit: report.date };
          setClients(clients.map(c => c.id === report.clientId ? newClientData : c));
          await api.saveClient(newClientData); // Async save client update
      }
    }

    await api.saveReport(report); // Async save report

    setSelectedTemplateKey(null);
    setSelectedClientForReport(null);
    setEditingReport(null);
    setViewingReport(null);
    setCurrentScreen(Screen.REPORTS);
  };

  const handleDownloadPDF = (report: Report) => {
    const client = clients.find(c => c.id === report.clientId);
    if (!client) return;
    const doc = generatePDF(report, client, companySettings);
    doc.save(`Relatorio_${client.name.replace(/\s+/g, '_')}_${report.date}.pdf`);
  };

  const handleEmailReport = (report: Report) => {
    const client = clients.find(c => c.id === report.clientId);
    if (!client) return;

    const doc = generatePDF(report, client, companySettings);

    // Simulate Email
    const subject = encodeURIComponent(`Relatório de Intervenção - ${client.name} - ${report.date}`);
    const body = encodeURIComponent(`Estimado(a) ${client.contactPerson},\n\nSegue em anexo o relatório da intervenção realizada dia ${report.date}.\n\nCumprimentos,\n${companySettings.name}`);

    // Open mailto
    window.open(`mailto:${client.email}?subject=${subject}&body=${body}`);
    // Download PDF for attachment
    doc.save(`Relatorio_${client.name.replace(/\s+/g, '_')}_${report.date}.pdf`);
    alert("O cliente de email foi aberto. O PDF foi descarregado para que o possa anexar manualmente.");
  };

  const handleDeleteReport = async (id: string) => {
    if (currentUser?.role !== UserRole.ADMIN) return;
    if (confirm("Deseja apagar este relatório permanentemente?")) {
      setReports(reports.filter(r => r.id !== id));
      await api.deleteReport(id);
    }
  };

  const openGoogleMaps = (lat: number, lng: number) => {
    window.open(`https://www.google.com/maps/search/?api=1&query=${lat},${lng}`, '_blank');
  };

  // --- Actions: Company Settings ---
  const handleSaveCompanySettings = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (currentUser?.role !== UserRole.ADMIN) return;

    const formData = new FormData(e.currentTarget);
    const fileInput = e.currentTarget.elements.namedItem('logoFile') as HTMLInputElement;

    let logoUrl = companySettings.logoUrl;

    if (fileInput.files && fileInput.files[0]) {
       const file = fileInput.files[0];
       logoUrl = await new Promise((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
       });
    }

    const newSettings = {
      name: formData.get('name') as string,
      nif: formData.get('nif') as string,
      address: formData.get('address') as string,
      postalCode: formData.get('postalCode') as string,
      locality: formData.get('locality') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      website: formData.get('website') as string,
      logoUrl: logoUrl
    };

    setCompanySettings(newSettings);
    await api.saveSettings(newSettings);
    alert("Definições da empresa atualizadas.");
  };


  // --- Render ---

  // Loading Screen
  if (isLoading) {
      return (
          <div className="min-h-screen bg-gray-100 flex items-center justify-center">
              <div className="text-center">
                  <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
                  <p className="text-gray-600 font-medium">A carregar dados...</p>
              </div>
          </div>
